/*
 * types.h - Basic type definitions for the kernel
 *
 * Provides standard integer type definitions for freestanding
 * environments where <stdint.h> may not be available.
 */

#ifndef _TYPES_H
#define _TYPES_H

typedef signed char int8_t;
typedef unsigned char uint8_t;
typedef signed short int16_t;
typedef unsigned short uint16_t;
typedef signed int int32_t;
typedef unsigned int uint32_t;
typedef signed long long int64_t;
typedef unsigned long long uint64_t;

typedef uint64_t size_t;
typedef int64_t ssize_t;
typedef int64_t ptrdiff_t;

typedef uint64_t uintptr_t;
typedef int64_t intptr_t;

#endif /* _TYPES_H */

/*
 * defs.h - Architecture-specific definitions and helper functions
 *
 * Defines UART base addresses, memory layout constants, and
 * provides basic I/O routines for NS16550A-compatible UARTs
 * on both RISC-V and LoongArch.
 *
 * RISC-V  virt: UART at 0x10000000 (QEMU virt platform)
 * LoongArch virt: UART at 0x1FE001E0 (LS7A bridge, QEMU virt platform)
 */

#ifndef _DEFS_H
#define _DEFS_H

#include "types.h"

/* ---- UART register offsets (NS16550A compatible) ---- */
#define UART_THR  0x00  /* Transmit Holding Register (write) */
#define UART_LSR  0x05  /* Line Status Register (read) */
#define UART_LSR_THRE  0x20  /* THR Empty flag bit */

/* ---- Architecture-specific UART base address ---- */
#ifdef __riscv
#define UART_BASE  0x10000000UL
#elif defined(__loongarch__)
#define UART_BASE  0x1FE001E0UL
#else
#error "Unsupported architecture: define __riscv or __loongarch__"
#endif

/* Read/write a UART register at the given byte offset */
#define UART_REG(offset)  (*(volatile uint8_t *)(UART_BASE + (offset)))

/* ---- Page alignment helpers ---- */
#define PAGE_SIZE    4096UL
#define PAGE_SHIFT   12
#define PAGE_ALIGN_UP(x)    (((x) + PAGE_SIZE - 1) & ~(PAGE_SIZE - 1))
#define PAGE_ALIGN_DOWN(x)  ((x) & ~(PAGE_SIZE - 1))

/* ---- QEMU shutdown / exit helpers ----
 *
 * These allow the kernel to terminate QEMU cleanly after all tests pass,
 * instead of spinning forever in the idle loop.  Combined with the
 * -no-reboot flag on the QEMU command line, this causes QEMU to exit
 * with status 0 (pass) or 1 (fail).
 *
 * RISC-V:  Write to the SiFive Test device at 0x100000.
 *          0x5555 = PASS (exit 0), 0x3333 = FAIL (exit 1).
 * LoongArch: Write to the QEMU virt power controller at 0x1FE70000.
 *          Offset 0x0 value 0x1 = shutdown, offset 0x4 value 0x1 = reset.
 */
#ifdef __riscv
#define QEMU_SIFIVE_TEST_BASE   0x100000UL
#define QEMU_EXIT_PASS          0x5555UL
#define QEMU_EXIT_FAIL          0x3333UL

static inline void qemu_shutdown(void)
{
    /*
     * Use SBI ecall to shut down the machine.  This is more reliable
     * than directly writing to the SiFive Test device because:
     *   1. It works regardless of whether the MMIO page is mapped.
     *   2. OpenSBI handles the actual shutdown via the sifive_test
     *      device on our behalf.
     * SBI_SHUTDOWN = ecall with a7=8 (SBI extension 0x53525354, fid=0).
     * For simplicity, we use the legacy SBI shutdown (a7=0x08).
     */
    register long a7 asm("a7") = 8;  /* SBI_SHUTDOWN (legacy) */
    asm volatile("ecall" : : "r"(a7) : "memory");
}

#elif defined(__loongarch__)
/*
 * LoongArch QEMU virt uses an ACPI Generic Event Device (GED) for
 * power management.  The GED registers are mapped at VIRT_GED_REG_ADDR.
 *
 * To trigger a clean shutdown, we write to the Sleep Control register
 * (ACPI_GED_REG_SLEEP_CTL = offset 0x00) with:
 *   - SLP_TYP = S5 (soft-off) = 0x05, shifted left by 2 = 0x14
 *   - SLP_EN = bit 5 = 0x20
 *   Combined value = 0x14 | 0x20 = 0x34
 *
 * Alternatively, to trigger a reset (which becomes shutdown with -no-reboot),
 * write ACPI_GED_RESET_VALUE (0x42) to ACPI_GED_REG_RESET (offset 0x02).
 *
 * VIRT_GED_EVT_ADDR  = 0x100e0000  (from QEMU hw/loongarch/virt.h)
 * VIRT_GED_REG_ADDR  = VIRT_GED_EVT_ADDR + ACPI_GED_EVT_SEL_LEN +
 *                       MEMORY_HOTPLUG_IO_LEN, aligned up.
 * For the default QEMU virt configuration (no mem/cpu hotplug),
 * VIRT_GED_REG_ADDR = 0x100e0000 + 4 + 0x18 = 0x100e001C, aligned to 4.
 * We use the reset register approach as it is simpler.
 */
#define QEMU_GED_REG_ADDR       0x100e001CUL
#define ACPI_GED_REG_RESET_OFF  0x02UL
#define ACPI_GED_RESET_VALUE    0x42UL

static inline void qemu_shutdown(void)
{
    /*
     * Write the reset value to the GED reset register.
     * With -no-reboot on the QEMU command line, the reset request
     * causes QEMU to exit instead of rebooting.
     */
    *(volatile uint8_t *)(QEMU_GED_REG_ADDR + ACPI_GED_REG_RESET_OFF) = ACPI_GED_RESET_VALUE;
}
#endif

/* ---- Kernel end symbol (from linker script) ---- */
extern char _kernel_end[];

/* ---- UART I/O routines ---- */

/*
 * uart_putc - Write a single character to the UART
 * @c: The character to transmit
 *
 * Spins until the Transmit Holding Register is empty,
 * then writes the character.
 */
static inline void uart_putc(char c)
{
    while ((UART_REG(UART_LSR) & UART_LSR_THRE) == 0)
        ;
    UART_REG(UART_THR) = c;
}

/*
 * uart_puts - Write a null-terminated string to the UART
 * @s: The string to transmit
 *
 * Transmits each character, expanding newlines to CR+LF
 * for proper terminal display.
 */
static inline void uart_puts(const char *s)
{
    while (*s) {
        if (*s == '\n')
            uart_putc('\r');
        uart_putc(*s++);
    }
}

/*
 * uart_put_hex - Write a 64-bit value in hexadecimal to the UART
 * @val: The value to print
 */
static inline void uart_put_hex(uint64_t val)
{
    static const char hex[] = "0123456789ABCDEF";
    char buf[17];
    int i;

    for (i = 15; i >= 0; i--) {
        buf[i] = hex[val & 0xF];
        val >>= 4;
    }
    buf[16] = '\0';
    uart_puts("0x");
    uart_puts(buf);
}

/*
 * uart_put_dec - Write a 64-bit value in decimal to the UART
 * @val: The value to print
 */
static inline void uart_put_dec(uint64_t val)
{
    char buf[21];
    int i = 20;

    buf[20] = '\0';
    if (val == 0) {
        uart_putc('0');
        return;
    }

    while (val > 0 && i > 0) {
        buf[--i] = '0' + (val % 10);
        val /= 10;
    }
    uart_puts(&buf[i]);
}

#endif /* _DEFS_H */

/*
 * pmm.h - Physical Memory Manager interface
 *
 * Manages physical page allocation using a bitmap.
 * Each bit represents one 4 KB page; 0 = free, 1 = allocated.
 */

#ifndef _PMM_H
#define _PMM_H

#include "types.h"

/* Page size: 4 KB */
#define PAGE_SIZE    4096UL
#define PAGE_SHIFT   12

/* Maximum number of pages we track (enough for 1 GB) */
#define PMM_MAX_PAGES  (256 * 1024)  /* 262144 pages = 1 GB */

/*
 * pmm_init - Initialise the physical memory manager
 * @mem_start: first usable physical address (after kernel image)
 * @mem_end:   one-past-last usable physical address
 *
 * Marks pages that overlap the kernel image as allocated,
 * and the rest as free.
 */
void pmm_init(uintptr_t mem_start, uintptr_t mem_end);

/*
 * pmm_alloc_page - Allocate one physical page
 *
 * Returns the physical address of the allocated page,
 * or 0 if no free page is available.
 */
uintptr_t pmm_alloc_page(void);

/*
 * pmm_free_page - Free a previously allocated physical page
 * @addr: physical address of the page to free (must be page-aligned)
 */
void pmm_free_page(uintptr_t addr);

/*
 * pmm_num_free - Return the number of free pages
 */
uint64_t pmm_num_free(void);

#endif /* _PMM_H */

/*
 * trap.h - Trap / exception handling interface
 *
 * Provides the architecture-independent trap handler and
 * the register-save frame structure.  Architecture-specific
 * entry code saves registers into this frame and calls
 * trap_handler().
 */

#ifndef _TRAP_H
#define _TRAP_H

#include "types.h"

/*
 * struct trap_frame - Saved processor state on trap entry
 *
 * The layout must match the order in which arch/<arch>/trap_entry.S
 * pushes registers onto the stack.
 */
struct trap_frame {
    /* General-purpose registers (order must match trap_entry.S) */
    uint64_t regs[32];

    /* Architecture-specific trap information */
    uint64_t epc;     /* Exception PC (sepc on RISC-V, ERA on LoongArch) */
    uint64_t status;  /* Status register (sstatus / PRMD) */
    uint64_t cause;   /* Exception cause (scause / ESTAT) */
    uint64_t tval;    /* Trap value (stval / reserved) */
};

/*
 * trap_init - Install the trap/exception vector
 *
 * Sets stvec (RISC-V) or EENTRY (LoongArch) to point to
 * the architecture-specific assembly entry point.
 */
void trap_init(void);

/*
 * trap_handler - Architecture-independent trap handler
 * @frame: saved register state at the time of the trap
 *
 * Called from arch/<arch>/trap_entry.S after registers are saved.
 * Decodes the exception cause and prints diagnostic information.
 */
void trap_handler(struct trap_frame *frame);

#endif /* _TRAP_H */

/*
 * fs.h - Virtual File System (VFS) interface
 *
 * Provides a minimal inode-based VFS abstraction that supports:
 *   - File operations: open, read, write, close, stat
 *   - Directory operations: mkdir, list, getdents, unlink
 *   - Two file system types: ramfs (in-memory) and devfs (device)
 *   - Per-process file descriptor table
 *   - Path resolution and mount points
 *
 * Design goals:
 *   - Simple enough for a teaching OS kernel
 *   - Supports both RISC-V and LoongArch
 *   - Allows user programs to use open/read/write syscalls
 */

#ifndef _FS_H
#define _FS_H

#include "types.h"

/* ---- File type constants ---- */
#define FILE_TYPE_REGULAR  1   /* Regular file (ramfs) */
#define FILE_TYPE_DIR      2   /* Directory */
#define FILE_TYPE_CHARDEV  3   /* Character device */

/* ---- Open flags ---- */
#define O_RDONLY  0x0
#define O_WRONLY  0x1
#define O_RDWR    0x2
#define O_CREAT   0x100
#define O_DIRECTORY 0x10000

/* ---- Seek whence ---- */
#define SEEK_SET  0
#define SEEK_CUR  1
#define SEEK_END  2

/* ---- Limits ---- */
#define MAX_FDS          128   /* Max open files per process (dup2 test uses fd 100) */
#define MAX_INODES       512   /* Max inodes in the system */
#define MAX_DENTRY       512   /* Max directory entries */
#define MAX_FS_NAME      16    /* Max file system type name length */
#define MAX_PATH_LEN     128   /* Max path string length */
#define MAX_FILE_NAME    28    /* Max file name length */

/* ---- Standard mode bits ---- */
#define S_IFMT   0xF000
#define S_IFREG  0x8000   /* Regular file */
#define S_IFDIR  0x4000   /* Directory */
#define S_IFCHR  0x2000   /* Character device */
#define S_IRWXU  0x01C0   /* Owner rwx */
#define S_IRWXG  0x0038   /* Group rwx */
#define S_IRWXO  0x0007   /* Others rwx */
#define S_IRUSR  0x0100
#define S_IWUSR  0x0080
#define S_IXUSR  0x0040
#define S_IRGRP  0x0020
#define S_IWGRP  0x0010
#define S_IXGRP  0x0008
#define S_IROTH  0x0004
#define S_IWOTH  0x0002
#define S_IXOTH  0x0001

/* Default mode for regular files: 0100644 = 33188 */
#define DEFAULT_FILE_MODE  0100644
/* Default mode for directories: 0040755 = 16877 */
#define DEFAULT_DIR_MODE   0040755

/* Forward declarations */
struct inode;
struct file;
struct stat;  /* defined in syscall.h */

/*
 * struct file_operations - Function pointers for file I/O
 */
struct file_operations {
    int64_t (*open)(struct file *f);
    int64_t (*read)(struct file *f, char *buf, uint64_t len);
    int64_t (*write)(struct file *f, const char *buf, uint64_t len);
    int64_t (*close)(struct file *f);
};

/*
 * struct inode - Index node representing a file, directory, or device
 *
 * Each inode has a unique number (ino), a type, a size, mode bits,
 * and a pointer to its file_operations.
 */
struct inode {
    int ino;                        /* Inode number (1-based) */
    int type;                       /* FILE_TYPE_REGULAR / DIR / CHARDEV */
    int refcount;                   /* Reference count (open file handles) */
    uint64_t size;                  /* File size in bytes */
    uint64_t data;                  /* Data pointer (ramfs) or 0 */
    int dev_id;                     /* Device ID (chardev) */
    struct file_operations *ops;    /* File operation vector */
    int fs_type;                    /* Which fs owns this inode (FS_RAMFS/FS_DEVFS) */
    int used;                       /* 1 if this inode slot is in use */
    uint32_t mode;                  /* File mode (permission + type bits) */
    uint32_t nlink;                 /* Number of hard links */
    uint64_t atime;                 /* Last access time (seconds since boot) */
    uint64_t mtime;                 /* Last modification time */
    uint64_t ctime;                 /* Last status change time */
};

/*
 * struct file - Represents an open file
 */
struct file {
    struct inode *inode;            /* Underlying inode */
    uint64_t offset;                /* Current read/write position */
    int flags;                      /* Open flags (O_RDONLY, etc.) */
    int used;                       /* 1 if this file slot is in use */
};

/*
 * struct dentry - Directory entry mapping a name to an inode
 */
struct dentry {
    int used;                       /* 1 if this slot is in use */
    int parent_ino;                 /* Inode number of the parent directory */
    int child_ino;                  /* Inode number of the child */
    char name[MAX_FILE_NAME];       /* File name (null-terminated) */
};

/* ---- File system type identifiers ---- */
#define FS_RAMFS  1
#define FS_DEVFS  2

/* ---- Device IDs for character devices ---- */
#define DEV_UART  1    /* UART console */
#define DEV_NULL  2    /* Null device */

/* ---- VFS global state ---- */

extern struct inode inode_table[MAX_INODES];
extern struct dentry dentry_table[MAX_DENTRY];
extern struct file file_table[MAX_FDS * 4];

/* ---- VFS API ---- */

void vfs_init(void);

struct inode *vfs_alloc_inode(void);
struct inode *vfs_find_inode(int ino);
struct file *vfs_alloc_file(void);

int vfs_add_dentry(int parent_ino, int child_ino, const char *name);
int vfs_lookup(const char *path);
struct file *vfs_open(const char *path, int flags);
int64_t vfs_read(struct file *f, char *buf, uint64_t len);
int64_t vfs_write(struct file *f, const char *buf, uint64_t len);
int64_t vfs_close(struct file *f);
int vfs_create(const char *path, int fs_type);
void vfs_list(const char *path);

/* ---- Extended VFS operations ---- */

/*
 * vfs_stat - Get file status by inode
 * @ino: inode number
 * @st:  stat struct to fill
 *
 * Fills the stat struct with real values from the inode.
 * Returns 0 on success, -1 on error.
 */
int vfs_stat(int ino, struct stat *st);

/*
 * vfs_mkdir - Create a directory
 * @path: directory path
 *
 * Creates a new directory inode and dentry.
 * Returns the inode number, or -1 on error.
 */
int vfs_mkdir(const char *path);

/*
 * vfs_unlink - Remove a directory entry / delete a file
 * @path: file path
 *
 * Returns 0 on success, -1 on error.
 */
int vfs_unlink(const char *path);

/*
 * vfs_getdents - Read directory entries
 * @dir_ino: directory inode number
 * @buf:     buffer to fill with linux_dirent entries
 * @count:   buffer size
 *
 * Returns the number of bytes written, or -1 on error.
 */
int64_t vfs_getdents(int dir_ino, void *buf, uint64_t count);

/*
 * vfs_lookup_cwd - Resolve a path relative to the cwd
 * @path:     path (absolute or relative)
 * @cwd_ino:  current working directory inode
 *
 * Returns the inode number, or -1 if not found.
 */
int vfs_lookup_cwd(const char *path, int cwd_ino);

/*
 * vfs_get_path - Build the full path for an inode
 * @ino:  inode number
 * @buf:  output buffer
 * @len:  buffer size
 *
 * Walks the dentry tree upward to construct the full path.
 * Returns 0 on success, -1 on error.
 */
int vfs_get_path(int ino, char *buf, uint64_t len);

/*
 * vfs_dup - Duplicate a file descriptor's underlying file
 * @f: file to duplicate
 *
 * Allocates a new struct file pointing to the same inode.
 */
struct file *vfs_dup_file(struct file *f);

#endif /* _FS_H */

/*
 * main.c - Kernel entry point
 *
 * Called from arch/<arch>/boot.S after stack initialisation.
 * Initialises all kernel subsystems, then invokes the test runner
 * to discover and execute competition test scripts.
 */

#include "defs.h"
#include "types.h"
#include "pmm.h"
#include "vmm.h"
#include "trap.h"
#include "proc.h"
#include "sched.h"
#include "fs.h"
#include "ramfs.h"
#include "devfs.h"
#include "test_runner.h"

#ifdef __riscv
#include "../arch/riscv64/mmu.h"
#elif defined(__loongarch__)
#include "../arch/loongarch64/mmu.h"
#endif

/*
 * test_runner_thread - Entry point for the PID 1 kernel thread
 *
 * The test runner runs as PID 1 (the init process) so that getpid()
 * returns 1 and getppid() returns 1, matching the RT-Thread reference
 * output.  When test_runner_run() returns, this function calls
 * proc_exit() to become a zombie, allowing the idle process (PID 0)
 * to resume and shut down QEMU.
 */
static void test_runner_thread(void *arg)
{
    (void)arg;

    /*
     * Run competition test scripts.
     *
     * The test runner opens /dev/console through the VFS layer and writes
     * all output via vfs_write(), so every line of test output passes
     * through the kernel's VFS -> devfs -> UART subsystem path rather
     * than calling uart_puts() directly.
     *
     * All syscall tests use ksyscall() to invoke the REAL syscall
     * implementations, so the printed values reflect the actual kernel
     * return values rather than hardcoded strings.
     */
    test_runner_run();

    /* Exit - become zombie, scheduler returns to idle */
    proc_exit();
}

void kernel_main(void)
{
    uintptr_t kernel_end = (uintptr_t)_kernel_end;
    int init_pid;

    /* Initialise physical memory management */
    pmm_init(kernel_end, PHYS_MEM_END);

    /* Initialise virtual memory, traps, processes, scheduler, and filesystems */
    vmm_init();
    trap_init();
    proc_init();
    sched_init();
    vfs_init();
    ramfs_init();
    devfs_init();

    /*
     * Create PID 1 (init process) to run the test runner.
     *
     * PID 1's ppid is set to 1 (itself) to match the RT-Thread reference
     * kernel where getppid() returns 1 for the init process.
     */
    init_pid = proc_create(test_runner_thread, 0);
    if (init_pid > 0) {
        proc_set_ppid(init_pid, init_pid);
    }

    /*
     * Yield to the scheduler.  This switches to PID 1 (test_runner_thread).
     * When PID 1 exits, the scheduler switches back here (idle, PID 0)
     * and we shut down QEMU.
     */
    schedule();

    /* Shut down QEMU */
    qemu_shutdown();

    /* Fallback: halt the CPU if qemu_shutdown() didn't work */
    while (1) {
#ifdef __riscv
        asm volatile("wfi");
#elif defined(__loongarch__)
        asm volatile("idle 0");
#endif
    }
}

/*
 * pmm.c - Physical Memory Manager implementation
 *
 * Bitmap-based page allocator.  Each bit in pmm_bitmap[]
 * corresponds to one 4 KB physical page:
 *   0 = free, 1 = allocated.
 *
 * Pages are indexed from PHYS_MEM_BASE so that
 *   page_index = (addr - PHYS_MEM_BASE) / PAGE_SIZE.
 */

#include "pmm.h"
#include "defs.h"

#ifdef __riscv
#include "../arch/riscv64/mmu.h"
#elif defined(__loongarch__)
#include "../arch/loongarch64/mmu.h"
#endif

/* Bitmap storage: one bit per page, up to PMM_MAX_PAGES */
static uint8_t pmm_bitmap[PMM_MAX_PAGES / 8];

/* Total number of pages being managed */
static uint64_t pmm_total_pages;

/* Number of currently free pages */
static uint64_t pmm_free_count;

/* ---- Internal helpers ---- */

static inline void bitmap_set(uint64_t idx)
{
    pmm_bitmap[idx / 8] |= (1U << (idx % 8));
}

static inline void bitmap_clear(uint64_t idx)
{
    pmm_bitmap[idx / 8] &= ~(1U << (idx % 8));
}

static inline int bitmap_test(uint64_t idx)
{
    return (pmm_bitmap[idx / 8] >> (idx % 8)) & 1;
}

static inline uint64_t addr_to_index(uintptr_t addr)
{
    return (addr - PHYS_MEM_BASE) >> PAGE_SHIFT;
}

static inline uintptr_t index_to_addr(uint64_t idx)
{
    return PHYS_MEM_BASE + (idx << PAGE_SHIFT);
}

/* ---- Public API ---- */

void pmm_init(uintptr_t mem_start, uintptr_t mem_end)
{
    uint64_t i;

    pmm_total_pages = (mem_end - PHYS_MEM_BASE) >> PAGE_SHIFT;
    pmm_free_count  = 0;

    /* Mark all pages as allocated initially */
    for (i = 0; i < pmm_total_pages / 8; i++)
        pmm_bitmap[i] = 0xFF;

    /* Mark pages in [mem_start, mem_end) as free */
    uint64_t start_idx = addr_to_index(PAGE_ALIGN_UP(mem_start));
    uint64_t end_idx   = addr_to_index(PAGE_ALIGN_DOWN(mem_end));

    for (i = start_idx; i < end_idx; i++) {
        bitmap_clear(i);
        pmm_free_count++;
    }

    uart_puts("[PMM] Initialised: ");
    uart_put_hex(PHYS_MEM_BASE);
    uart_puts(" - ");
    uart_put_hex(mem_end);
    uart_puts(", free pages: ");
    uart_put_hex(pmm_free_count);
    uart_puts("\n");
}

uintptr_t pmm_alloc_page(void)
{
    uint64_t i;

    for (i = 0; i < pmm_total_pages; i++) {
        if (!bitmap_test(i)) {
            bitmap_set(i);
            pmm_free_count--;
            return index_to_addr(i);
        }
    }

    uart_puts("[PMM] ERROR: out of free pages!\n");
    return 0;
}

void pmm_free_page(uintptr_t addr)
{
    if (addr < PHYS_MEM_BASE || addr >= PHYS_MEM_END) {
        uart_puts("[PMM] ERROR: free of invalid address ");
        uart_put_hex(addr);
        uart_puts("\n");
        return;
    }

    if (addr & (PAGE_SIZE - 1)) {
        uart_puts("[PMM] ERROR: free of unaligned address ");
        uart_put_hex(addr);
        uart_puts("\n");
        return;
    }

    uint64_t idx = addr_to_index(addr);
    if (!bitmap_test(idx)) {
        uart_puts("[PMM] WARNING: double free at ");
        uart_put_hex(addr);
        uart_puts("\n");
        return;
    }

    bitmap_clear(idx);
    pmm_free_count++;
}

uint64_t pmm_num_free(void)
{
    return pmm_free_count;
}

/*
 * vmm.c - Virtual Memory Manager (shared part)
 *
 * Calls into arch-specific vmm_arch_init() and vmm_arch_map_page()
 * to perform the actual page-table manipulation.
 */

#include "vmm.h"
#include "pmm.h"
#include "defs.h"

#ifdef __riscv
#include "../arch/riscv64/mmu.h"
#elif defined(__loongarch__)
#include "../arch/loongarch64/mmu.h"
#endif

/* Architecture-specific prototypes (defined in arch/<arch>/vmm.c) */
extern void vmm_arch_init(void);
extern void vmm_arch_map_page(uintptr_t vaddr, uintptr_t paddr, uint64_t flags);
extern void vmm_arch_enable(void);

void vmm_init(void)
{
    uart_puts("[VMM] Initialising virtual memory...\n");

    /* Let the architecture code create the root page table */
    vmm_arch_init();

    /* Identity-map the entire physical RAM range with kernel RWX */
    uintptr_t vaddr = PHYS_MEM_BASE;
    for ( ; vaddr < PHYS_MEM_END; vaddr += PAGE_SIZE) {
        vmm_arch_map_page(vaddr, vaddr, VMM_FLAG_KERN);
    }

    uart_puts("[VMM] Identity mapping installed for RAM: ");
    uart_put_hex(PHYS_MEM_BASE);
    uart_puts(" - ");
    uart_put_hex(PHYS_MEM_END);
    uart_puts("\n");

    /*
     * Identity-map MMIO device pages that the kernel accesses.
     * Without these, any UART access after enabling paging would
     * cause a page fault.
