#ifdef __riscv
    /* RISC-V QEMU virt: UART at 0x10000000 */
    vmm_arch_map_page(0x10000000UL, 0x10000000UL, VMM_FLAG_KERN_RW);
    uart_puts("[VMM] Mapped UART device at 0x10000000\n");
    /* RISC-V QEMU virt: SiFive Test device at 0x100000 (for qemu_shutdown) */
    vmm_arch_map_page(0x100000UL, 0x100000UL, VMM_FLAG_KERN_RW);
    uart_puts("[VMM] Mapped SiFive Test device at 0x100000\n");
#elif defined(__loongarch__)
    /* LoongArch QEMU virt: UART at 0x1FE001E0, map the page containing it */
    vmm_arch_map_page(0x1FE00000UL, 0x1FE00000UL, VMM_FLAG_KERN_RW);
    uart_puts("[VMM] Mapped UART device at 0x1FE00000\n");
    /* LoongArch QEMU virt: ACPI GED registers at 0x100e0000 (for qemu_shutdown) */
    vmm_arch_map_page(0x100e0000UL, 0x100e0000UL, VMM_FLAG_KERN_RW);
    uart_puts("[VMM] Mapped ACPI GED registers at 0x100e0000\n");
#endif

    /* Enable paging (architecture-specific) */
    vmm_arch_enable();

    uart_puts("[VMM] Paging enabled.\n");
}

