/* ---- RISC-V exception names ---- */
#ifdef __riscv
static const char *riscv_exc_name(uint64_t cause)
{
    switch (cause) {
    case 0:  return "Instruction address misaligned";
    case 1:  return "Instruction access fault";
    case 2:  return "Illegal instruction";
    case 3:  return "Breakpoint";
    case 4:  return "Load address misaligned";
    case 5:  return "Load access fault";
    case 6:  return "Store/AMO address misaligned";
    case 7:  return "Store/AMO access fault";
    case 8:  return "ECALL from U-mode";
    case 9:  return "ECALL from S-mode";
    case 12: return "Instruction page fault";
    case 13: return "Load page fault";
    case 15: return "Store/AMO page fault";
    default: return "Unknown exception";
    }
}
#endif

/* ---- LoongArch exception names ---- */
#ifdef __loongarch__
static const char *loongarch_exc_name(uint64_t ecode)
{
    switch (ecode) {
    case EXC_INE: return "Invalid Non-Existent instruction";
    case EXC_IPE: return "Instruction Privilege Error";
    case EXC_FPE: return "Floating Point Exception";
    case EXC_FPD: return "Floating Point Disabled";
    case EXC_ADE: return "Address Error";
    case EXC_ALE: return "Address Alignment Error";
    case EXC_BCE: return "Bound Check Error";
    case EXC_SYS: return "System Call";
    case EXC_BRK: return "Breakpoint";
    case EXC_PIL: return "Page Invalid for Load";
    case EXC_PIS: return "Page Invalid for Store";
    case EXC_PIF: return "Page Invalid for Fetch";
    case EXC_PME: return "Page Modified Error";
    case EXC_PNR: return "Page Not Readable";
    case EXC_PXN: return "Page Not Executable";
    case EXC_PPI: return "Page Privilege Illegal";
    default:      return "Unknown exception";
    }
}
#endif

void trap_handler(struct trap_frame *frame)
{
