    int is_interrupt = (cause >> 63) & 1;
    uint64_t code = cause & 0x7FFFFFFFFFFFFFFFUL;

    /* ---- Handle timer interrupt (Supervisor Timer Interrupt, code 5) ---- */
    if (is_interrupt && code == 5) {
        sched_tick();
        return;
    }

    /* ---- Handle ECALL from U-mode (exception code 8) ---- */
    if (!is_interrupt && code == 8) {
        /*
         * System call from user mode.
         * RISC-V convention: a7 = syscall number, a0-a5 = arguments.
         * Register layout in trap_frame:
         *   regs[10] = a0, regs[11] = a1, regs[12] = a2
         *   regs[17] = a7
         */
        uint64_t sys_num = frame->regs[17];  /* a7 */
        uint64_t a0      = frame->regs[10];  /* a0 */
        uint64_t a1      = frame->regs[11];  /* a1 */
        uint64_t a2      = frame->regs[12];  /* a2 */

        int64_t ret = syscall_handler(sys_num, a0, a1, a2);

        /* Write return value to a0 */
        frame->regs[10] = (uint64_t)ret;

        /* Advance SEPC past the ecall instruction (4 bytes) */
        frame->epc += 4;
        return;
    }

    uart_puts("\n[TRAP] === Exception caught ===\n");

    if (is_interrupt) {
        uart_puts("[TRAP] Interrupt, code: ");
    } else {
        uart_puts("[TRAP] Exception: ");
        uart_puts(riscv_exc_name(code));
        uart_puts(" (code ");
    }
    uart_put_hex(code);
    uart_puts(")\n");

    uart_puts("[TRAP] SEPC:   ");
    uart_put_hex(frame->epc);
    uart_puts("\n");
    uart_puts("[TRAP] STVAL:  ");
    uart_put_hex(frame->tval);
    uart_puts("\n");

    /* For breakpoint (ebreak), skip the instruction by advancing SEPC */
    if (code == 3) {
        /*
         * RISC-V compressed (16-bit) instructions have their
         * low two bits != 11.  Detect the instruction length
         * and advance SEPC accordingly.
         */
        uint16_t inst = *(uint16_t *)frame->epc;
        if ((inst & 0x3) != 0x3)
            frame->epc += 2;   /* 16-bit compressed instruction (c.ebreak) */
        else
            frame->epc += 4;   /* 32-bit instruction */
        uart_puts("[TRAP] Breakpoint: advancing EPC\n");
    }

#elif defined(__loongarch__)
    uint64_t ecode = (frame->cause >> ESTAT_ECODE_SHIFT) & ESTAT_ECODE_MASK;

    /*
     * ---- Handle timer interrupt ----
     * LoongArch timer interrupt has ecode = 0 with the interrupt
     * type indicated by the IS (Interrupt Source) bits in ESTAT.
     * Bit 11 (TIO) in ESTAT indicates a timer interrupt.
     * We check: ecode == 0 and ESTAT bit 11 is set.
