/*
 * proc.c - Process management implementation
 *
 * Manages the process table, creates kernel threads, and
 * provides utilities for process state transitions.
 *
 * Supports fork (create child copy), wait/waitpid (reap children),
 * brk (program break tracking), and cwd (current working directory).
 */

#include "proc.h"
#include "sched.h"
#include "pmm.h"
#include "defs.h"
#include "syscall.h"
#include "vmm.h"

/* ---- Process table ---- */
static struct proc proc_table[MAX_PROCS];

/* ---- Currently running process ---- */
static struct proc *current_proc;

/*
 * current_kernel_sp - Kernel stack pointer for the current user process
 */
uint64_t current_kernel_sp;

/* ---- Helper: find an unused PCB slot ---- */
static struct proc *find_unused(void)
{
    int i;
    for (i = 0; i < MAX_PROCS; i++) {
        if (proc_table[i].state == PROC_UNUSED)
            return &proc_table[i];
    }
    return 0;
}

/*
 * alloc_pid - Allocate the lowest available PID.
 *
 * PIDs are recycled when processes exit and are reaped, keeping
 * them within a small range.  This prevents out-of-bounds accesses
 * in arrays indexed by PID (e.g. yield_child_id[MAX_PROCS]).
 */
static int alloc_pid(void)
{
    int pid = 1;
    for (;;) {
        int taken = 0;
        int i;
        for (i = 0; i < MAX_PROCS; i++) {
            if (proc_table[i].state != PROC_UNUSED &&
                proc_table[i].pid == pid) {
                taken = 1;
                break;
            }
        }
        if (!taken)
            return pid;
        pid++;
    }
}

/* ---- Helper: find a PCB by PID ---- */
static struct proc *find_by_pid(int pid)
{
    int i;
    for (i = 0; i < MAX_PROCS; i++) {
        if (proc_table[i].state != PROC_UNUSED && proc_table[i].pid == pid)
            return &proc_table[i];
    }
    return 0;
}

/*
 * proc_entry_wrapper - Assembly trampoline entry for new threads
 */
void proc_entry_wrapper(void)
{
    struct proc *p = proc_current();

    if (p->is_user) {
        enter_user_mode(p->user_entry, p->user_stack_top, p->user_arg);
        proc_exit();
    }

    void (*entry)(void *) = (void (*)(void *))p->ctx.s[0];
    void *arg = (void *)p->ctx.s[1];

    entry(arg);

    proc_exit();
}

void proc_init(void)
{
    int i;

    for (i = 0; i < MAX_PROCS; i++) {
        proc_table[i].state = PROC_UNUSED;
        proc_table[i].pid = 0;
        proc_table[i].ppid = 0;
    }

    current_proc = &proc_table[0];
    current_proc->pid = 0;
    current_proc->ppid = 0;
    current_proc->state = PROC_RUNNING;
    current_proc->is_user = 0;
    current_proc->stack = 0;
    current_proc->stack_top = 0;
    current_proc->user_entry = 0;
    current_proc->user_stack_top = 0;
    current_proc->priority = 0;
    current_proc->ticks = 0;
    current_proc->total_ticks = 0;
    current_proc->brk = INITIAL_BRK;
    current_proc->cwd_ino = 1;  /* root directory */
    current_proc->exit_code = 0;
    current_proc->fork_ret = 0;
    current_proc->signal_pending = 0;
    current_proc->signal_mask = 0;
    for (i = 0; i < 32; i++)
        current_proc->signal_handlers[i] = 0;

    for (i = 0; i < MAX_FDS; i++) {
        current_proc->fds[i] = 0;
    }

    uart_puts("[PROC] Process subsystem initialised\n");
}

int proc_create(void (*entry)(void *arg), void *arg)
{
    struct proc *p = find_unused();
    if (!p) {
        uart_puts("[PROC] ERROR: no free PCB slots\n");
        return -1;
    }

    uintptr_t stack_page = pmm_alloc_page();
    if (stack_page == 0) {
        uart_puts("[PROC] ERROR: no free pages for stack\n");
        return -1;
    }

    p->pid = alloc_pid();
    p->ppid = current_proc ? current_proc->pid : 0;

    p->stack = stack_page;
    p->stack_top = stack_page + PAGE_SIZE;

    p->state = PROC_READY;
    p->is_user = 0;
    p->user_entry = 0;
    p->user_stack_top = 0;
    p->priority = 1;
    p->ticks = 0;
    p->total_ticks = 0;
    p->brk = INITIAL_BRK;
    p->cwd_ino = current_proc ? current_proc->cwd_ino : 1;
    p->exit_code = 0;
    p->fork_ret = 0;
    p->signal_pending = 0;
    p->signal_mask = 0;
    {
        int si;
        for (si = 0; si < 32; si++)
            p->signal_handlers[si] = 0;
    }

    {
        int fi;
        for (fi = 0; fi < MAX_FDS; fi++) {
            p->fds[fi] = 0;
        }
    }

    p->ctx.ra = (uint64_t)proc_entry_wrapper;
    p->ctx.sp = p->stack_top;
    p->ctx.s[0] = (uint64_t)entry;
    p->ctx.s[1] = (uint64_t)arg;

    p->ctx.s[2] = 0;
    p->ctx.s[3] = 0;
    p->ctx.s[4] = 0;
    p->ctx.s[5] = 0;
    p->ctx.s[6] = 0;
    p->ctx.s[7] = 0;
    p->ctx.s[8] = 0;
    p->ctx.s[9] = 0;
    p->ctx.s[10] = 0;
    p->ctx.s[11] = 0;

    return p->pid;
}

struct proc *proc_current(void)
{
    return current_proc;
}

void proc_yield(void)
{
    if (current_proc) {
        current_proc->state = PROC_READY;
    }
    schedule();
}

void proc_exit(void)
{
    proc_exit_code(0);
}

void proc_exit_code(int code)
{
    struct proc *cur = current_proc;
    if (!cur) {
        while (1) ;
    }

    cur->exit_code = code;
    cur->state = PROC_ZOMBIE;

    /*
     * Wake up the parent if it is blocked waiting for a child.
     * The parent's PCB is found by ppid.
     */
    if (cur->ppid > 0) {
        struct proc *parent = find_by_pid(cur->ppid);
        if (parent && parent->state == PROC_BLOCKED) {
            parent->state = PROC_READY;
        }
    }

    schedule();

    uart_puts("[PROC] FATAL: proc_exit returned!\n");
    while (1) ;
}

void proc_dump(void)
{
    int i;
    uart_puts("\n[PROC] === Process Table ===\n");
    for (i = 0; i < MAX_PROCS; i++) {
        struct proc *p = &proc_table[i];
        if (p->state == PROC_UNUSED)
            continue;

        const char *state_str;
        switch (p->state) {
        case PROC_READY:   state_str = "READY";   break;
        case PROC_RUNNING: state_str = "RUNNING"; break;
        case PROC_BLOCKED: state_str = "BLOCKED"; break;
        case PROC_ZOMBIE:  state_str = "ZOMBIE";  break;
