        uart_put_dec(p->ppid);
        uart_puts(" state=");
        uart_puts(state_str);
        uart_puts(" ticks=");
        uart_put_dec(p->total_ticks);
        uart_puts("\n");
    }
    uart_puts("[PROC] === End Table ===\n");
}

