/*
 * proc_wait - Wait for any child process to exit
 */
int proc_wait(int *status)
{
    struct proc *parent = current_proc;
    int i;

    if (!parent)
        return -1;

    /* First, check if any child is already a zombie */
    for (;;) {
        for (i = 0; i < MAX_PROCS; i++) {
            struct proc *p = &proc_table[i];
            if (p->state == PROC_ZOMBIE && p->ppid == parent->pid) {
                int pid = p->pid;
                int code = p->exit_code;
                /* Reap: free the PCB */
                p->state = PROC_UNUSED;
                p->pid = 0;
                if (status)
                    *status = code;
                return pid;
            }
        }

        /* No zombie child found; check if any child exists */
        int has_child = 0;
        for (i = 0; i < MAX_PROCS; i++) {
            if (proc_table[i].state != PROC_UNUSED &&
                proc_table[i].ppid == parent->pid &&
                proc_table[i].state != PROC_ZOMBIE) {
                has_child = 1;
                break;
            }
        }

        if (!has_child)
            return -1;  /* No children to wait for */

        /* Block and let children run */
        parent->state = PROC_BLOCKED;
        schedule();
        /* Resumed: loop to check for zombies again */
    }
}

/*
 * proc_waitpid - Wait for a specific child process
 */
int proc_waitpid(int pid, int *status, int options)
{
    struct proc *parent = current_proc;
    struct proc *child;

    (void)options;

    if (!parent)
        return -1;

    for (;;) {
        child = find_by_pid(pid);
        if (!child || child->ppid != parent->pid)
            return -1;

        if (child->state == PROC_ZOMBIE) {
            int code = child->exit_code;
            child->state = PROC_UNUSED;
            child->pid = 0;
            if (status)
                *status = code;
            return pid;
        }

        /* Block and let the child run */
        parent->state = PROC_BLOCKED;
        schedule();
    }
}

