    if (!p)
        return 0;

    if (new_brk == 0)
        return p->brk;  /* Query current break */

    /* Set the new break */
    p->brk = new_brk;
    return p->brk;
}

int proc_get_cwd(void)
{
    struct proc *p = proc_current();
    return p ? p->cwd_ino : 1;
}

void proc_set_cwd(int ino)
{
    struct proc *p = proc_current();
    if (p)
        p->cwd_ino = ino;
}

/*
 * proc_create_user - Create a new user-mode process
 *
 * @entry:     user-mode entry point
 * @stack_top: user-mode stack top
 * @arg:       argument passed to the user program via s0 register
 */
int proc_create_user(uint64_t entry, uint64_t stack_top, uint64_t arg)
{
    struct proc *p = find_unused();
    if (!p) {
        uart_puts("[PROC] ERROR: no free PCB slots\n");
        return -1;
    }

    uintptr_t stack_page = pmm_alloc_page();
    if (stack_page == 0) {
        uart_puts("[PROC] ERROR: no free pages for kernel stack\n");
        return -1;
    }

    p->pid = alloc_pid();
    p->ppid = current_proc ? current_proc->pid : 0;

    p->stack = stack_page;
    p->stack_top = stack_page + PAGE_SIZE;

    p->state = PROC_READY;
    p->is_user = 1;
    p->user_entry = entry;
    p->user_stack_top = stack_top;
    p->user_arg = arg;
    p->priority = 1;
    p->ticks = 0;
    p->total_ticks = 0;
    p->brk = INITIAL_BRK;
    p->cwd_ino = current_proc ? current_proc->cwd_ino : 1;
    p->exit_code = 0;
    p->fork_ret = 0;
    p->signal_pending = 0;
    p->signal_mask = 0;
    {
        int si;
        for (si = 0; si < 32; si++)
            p->signal_handlers[si] = 0;
    }

    {
        int fi;
        for (fi = 0; fi < MAX_FDS; fi++) {
            p->fds[fi] = 0;
        }
    }

    p->ctx.ra = (uint64_t)proc_entry_wrapper;
    p->ctx.sp = p->stack_top;
    p->ctx.s[0] = 0;
    p->ctx.s[1] = 0;

    /* Map the user stack page (USER_STACK_TOP - 0x1000 .. USER_STACK_TOP) */
    {
        uintptr_t user_stack_phys = pmm_alloc_page();
        if (user_stack_phys != 0) {
            /* Zero the stack page */
            for (int i = 0; i < 1024; i++)
                ((uint64_t *)user_stack_phys)[i] = 0;
            /* Map at (USER_STACK_TOP - PAGE_SIZE) with RW permissions
             * (NO U bit initially, so S-mode can write to it) */
            vmm_arch_map_page((uintptr_t)(stack_top - 0x1000),
                              user_stack_phys,
                              VMM_FLAG_READ | VMM_FLAG_WRITE);
            /* Now add User permission so U-mode can access the stack */
            vmm_arch_set_user_bit((uintptr_t)(stack_top - 0x1000));
        }
    }
    p->ctx.s[2] = 0;
    p->ctx.s[3] = 0;
    p->ctx.s[4] = 0;
    p->ctx.s[5] = 0;
    p->ctx.s[6] = 0;
    p->ctx.s[7] = 0;
    p->ctx.s[8] = 0;
    p->ctx.s[9] = 0;
    p->ctx.s[10] = 0;
    p->ctx.s[11] = 0;

    return p->pid;
}

void proc_set_current(struct proc *p)
{
    current_proc = p;
    p->state = PROC_RUNNING;
    p->ticks = 0;

    if (p->is_user) {
        current_kernel_sp = p->stack_top;
    }
}

