/*
 * sched.c - Round-robin scheduler implementation
 *
 * Picks the next READY process from the process table in
 * circular order and performs a context switch via switch_to().
 */

#include "sched.h"
#include "proc.h"
#include "defs.h"

/* ---- Scheduler state ---- */
static int sched_last_idx;   /* Index of the last process that ran */

void sched_init(void)
{
    sched_last_idx = 0;

    /* Enable the architecture-specific timer */
    timer_enable();

    uart_puts("[SCHED] Scheduler initialised, time quantum=");
    uart_put_dec(SCHED_TIME_QUANTUM);
    uart_puts(" ticks\n");
}

void sched_tick(void)
{
    struct proc *cur = proc_current();
    if (cur) {
        cur->ticks++;
        cur->total_ticks++;

        /* Preempt if time quantum expired */
        if (cur->ticks >= SCHED_TIME_QUANTUM) {
            cur->state = PROC_READY;
            schedule();
        }
    }

    /* Reset the timer for the next tick */
    timer_reset();
}

void schedule(void)
{
    struct proc *table = proc_table_ptr();
    struct proc *cur = proc_current();
    struct proc *next = 0;
    int i, idx;
    int start;

    /*
     * Search for the next READY process, starting just after
     * the last scheduled process and wrapping around.
     * Skip PID 0 (idle process) in the round-robin search
     * because the idle process should only run when no other
     * process is ready.
     */
    start = (sched_last_idx + 1) % MAX_PROCS;
    for (i = 0; i < MAX_PROCS; i++) {
        idx = (start + i) % MAX_PROCS;
        if (table[idx].state == PROC_READY && table[idx].pid != 0) {
            next = &table[idx];
            break;
        }
    }

    /* No runnable process: switch back to idle (PID 0) */
    if (!next) {
        if (cur && cur->state == PROC_RUNNING) {
            cur->ticks = 0;
            return;
        }
        /*
         * All user threads are blocked/zombie.  Switch back to
         * the idle process (PID 0) so it can continue execution
         * (e.g. print the self-test result and halt).
         */
        next = &table[0];  /* idle process is always at index 0 */
        if (next->state == PROC_READY) {
            sched_last_idx = 0;
            proc_set_current(next);
            if (cur && cur != next) {
                switch_to(&cur->ctx, &next->ctx);
            }
        } else {
            /* Idle is already RUNNING (shouldn't happen) */
            while (1) {
#ifdef __riscv
                asm volatile("wfi");
#elif defined(__loongarch__)
                asm volatile("idle 0");
#endif
            }
        }
        return;
    }

    /* If current is still RUNNING, demote to READY */
    if (cur && cur->state == PROC_RUNNING) {
        cur->state = PROC_READY;
    }

    /* Update scheduler state */
    sched_last_idx = next - table;

    /* Mark next as RUNNING */
    proc_set_current(next);

    /* Perform the context switch */
    if (cur && cur != next) {
        switch_to(&cur->ctx, &next->ctx);
    } else if (!cur) {
        /* First ever switch: no previous context to save */
        switch_to(0, &next->ctx);
    }
    /* If cur == next, we're already running the right process */
}

/*
 * fs.c - Virtual File System (VFS) implementation
 *
 * Implements the core VFS operations: inode allocation, path
 * resolution, open/read/write/close dispatch, stat, mkdir,
 * unlink, getdents, and dentry management.
 */

#include "fs.h"
#include "pmm.h"
#include "defs.h"
#include "syscall.h"  /* for struct stat definition used by vfs_stat */

/* ---- Global tables ---- */
struct inode  inode_table[MAX_INODES];
struct dentry dentry_table[MAX_DENTRY];
struct file   file_table[MAX_FDS * 4];

/* ---- Next inode number to allocate ---- */
static int next_ino = 1;

/* ---- Helper: string length ---- */
static int my_strlen(const char *s)
{
    int n = 0;
    while (*s++) n++;
    return n;
}

/* ---- Helper: string compare ---- */
static int my_strcmp(const char *a, const char *b)
{
    while (*a && *b && *a == *b) { a++; b++; }
    return (unsigned char)*a - (unsigned char)*b;
}

/* ---- Helper: string copy ---- */
static void my_strcpy(char *dst, const char *src)
{
    while ((*dst++ = *src++))
        ;
}

/* ---- Helper: extract last component from a path ---- */
static const char *path_basename(const char *path)
{
    const char *p = path;
    const char *last = path;

    while (*p) {
        if (*p == '/')
            last = p + 1;
        p++;
    }
    return last;
}

/* ---- Helper: extract parent directory path ---- */
static int path_parent(const char *path, char *parent, uint64_t parent_len)
{
    int len = my_strlen(path);
    int i;

    if (len <= 1) {
        parent[0] = '/';
        parent[1] = '\0';
        return 0;
    }

    for (i = len - 1; i > 0; i--) {
        if (path[i] == '/')
            break;
    }

    if (i == 0) {
        parent[0] = '/';
        parent[1] = '\0';
    } else {
        if ((uint64_t)i >= parent_len)
            i = (int)(parent_len - 1);
        int j;
        for (j = 0; j < i; j++)
            parent[j] = path[j];
        parent[j] = '\0';
    }
    return 0;
}

/* ---- VFS initialisation ---- */
void vfs_init(void)
{
    int i;

    for (i = 0; i < MAX_INODES; i++) {
        inode_table[i].used = 0;
        inode_table[i].ino = 0;
        inode_table[i].refcount = 0;
        inode_table[i].mode = 0;
        inode_table[i].nlink = 0;
        inode_table[i].atime = 0;
        inode_table[i].mtime = 0;
        inode_table[i].ctime = 0;
    }

    for (i = 0; i < MAX_DENTRY; i++) {
        dentry_table[i].used = 0;
    }

    for (i = 0; i < MAX_FDS * 4; i++) {
        file_table[i].used = 0;
    }

    next_ino = 1;

    uart_puts("[VFS] Virtual File System initialised\n");
}

/* ---- Inode allocation ---- */
struct inode *vfs_alloc_inode(void)
{
    int i;
    for (i = 0; i < MAX_INODES; i++) {
        if (!inode_table[i].used) {
            struct inode *ino = &inode_table[i];
            ino->used = 1;
            ino->ino = next_ino++;
            ino->type = 0;
            ino->refcount = 0;
            ino->size = 0;
            ino->data = 0;
            ino->dev_id = 0;
            ino->ops = 0;
            ino->fs_type = 0;
            ino->mode = 0;
            ino->nlink = 1;
            ino->atime = 1;
            ino->mtime = 1;
            ino->ctime = 1;
            return ino;
        }
    }
    uart_puts("[VFS] ERROR: no free inode slots\n");
    return 0;
}

/* ---- Inode lookup ---- */
struct inode *vfs_find_inode(int ino)
{
    int i;
    for (i = 0; i < MAX_INODES; i++) {
        if (inode_table[i].used && inode_table[i].ino == ino)
            return &inode_table[i];
    }
    return 0;
}

/* ---- File slot allocation ---- */
struct file *vfs_alloc_file(void)
{
    int i;
    for (i = 0; i < MAX_FDS * 4; i++) {
        if (!file_table[i].used) {
            struct file *f = &file_table[i];
            f->used = 1;
            f->inode = 0;
            f->offset = 0;
            f->flags = 0;
            return f;
        }
    }
    uart_puts("[VFS] ERROR: no free file slots\n");
    return 0;
}

/* ---- Dentry management ---- */
int vfs_add_dentry(int parent_ino, int child_ino, const char *name)
{
    int i;

    if (my_strlen(name) >= MAX_FILE_NAME) {
        uart_puts("[VFS] ERROR: file name too long: ");
        uart_puts(name);
        uart_puts("\n");
        return -1;
    }

    for (i = 0; i < MAX_DENTRY; i++) {
        if (dentry_table[i].used &&
            dentry_table[i].parent_ino == parent_ino &&
            my_strcmp(dentry_table[i].name, name) == 0) {
            return 0;
        }
    }

    for (i = 0; i < MAX_DENTRY; i++) {
        if (!dentry_table[i].used) {
            dentry_table[i].used = 1;
            dentry_table[i].parent_ino = parent_ino;
            dentry_table[i].child_ino = child_ino;
            my_strcpy(dentry_table[i].name, name);
            return 0;
        }
    }

    uart_puts("[VFS] ERROR: no free dentry slots\n");
    return -1;
}

/* ---- Path resolution (absolute) ---- */
int vfs_lookup(const char *path)
{
    int current_ino;
    int i;
    const char *p;

    if (!path || path[0] != '/') {
        return -1;
    }

    if (path[1] == 'd' && path[2] == 'e' && path[3] == 'v') {
        if (path[4] == '/' || path[4] == '\0') {
            if (path[4] == '\0') {
                return 2;
            }
            current_ino = 2;
            p = path + 5;
        } else {
            current_ino = 1;
            p = path + 1;
        }
    } else if (path[1] == '\0') {
        return 1;
    } else {
        current_ino = 1;
        p = path + 1;
    }

    while (*p) {
        char component[MAX_FILE_NAME];
        int ci = 0;

        while (*p && *p != '/' && ci < MAX_FILE_NAME - 1) {
            component[ci++] = *p++;
        }
        component[ci] = '\0';

        if (ci == 0) {
            if (*p == '/') p++;
            continue;
        }

        int found = 0;
        for (i = 0; i < MAX_DENTRY; i++) {
            if (dentry_table[i].used &&
                dentry_table[i].parent_ino == current_ino &&
                my_strcmp(dentry_table[i].name, component) == 0) {
                current_ino = dentry_table[i].child_ino;
                found = 1;
                break;
            }
        }

        if (!found) {
            return -1;
        }

        if (*p == '/') p++;
    }

    return current_ino;
}

/* ---- Path resolution (relative to cwd) ---- */
int vfs_lookup_cwd(const char *path, int cwd_ino)
{
    if (!path)
        return -1;

    /* Absolute path: use normal lookup */
    if (path[0] == '/')
        return vfs_lookup(path);

    /* Relative path: start from cwd */
