        /* Build the cwd path */
        if (vfs_get_path(cwd_ino, cwd_path, MAX_PATH_LEN) < 0)
            return -1;

        cwd_len = my_strlen(cwd_path);
        if (cwd_len + 1 + my_strlen(path) + 1 >= MAX_PATH_LEN)
            return -1;

        /* Build full path: cwd + "/" + path */
        int j = 0;
        int k;
        for (k = 0; k < cwd_len; k++)
            full[j++] = cwd_path[k];
        if (j > 0 && full[j-1] != '/')
            full[j++] = '/';
        k = 0;
        while (path[k])
            full[j++] = path[k];
        full[j] = '\0';

        return vfs_lookup(full);
    }
}

