/* ---- Open ---- */
struct file *vfs_open(const char *path, int flags)
{
    int ino_num;
    struct inode *inode;
    struct file *f;

    ino_num = vfs_lookup(path);

    if (ino_num < 0) {
        if (flags & O_CREAT) {
            ino_num = vfs_create(path, FS_RAMFS);
            if (ino_num < 0)
                return 0;
        } else {
            return 0;
        }
    }

    inode = vfs_find_inode(ino_num);
    if (!inode) return 0;

    f = vfs_alloc_file();
    if (!f) return 0;

    f->inode = inode;
    f->offset = 0;
    f->flags = flags;
    inode->refcount++;

    if (inode->ops && inode->ops->open) {
        int64_t ret = inode->ops->open(f);
        if (ret < 0) {
            f->used = 0;
            inode->refcount--;
            return 0;
        }
    }

    return f;
}

/* ---- Read ---- */
int64_t vfs_read(struct file *f, char *buf, uint64_t len)
{
    if (!f || !f->used || !f->inode)
        return -1;

    if ((f->flags & 0x3) == O_WRONLY)
        return -1;

    if (f->inode->ops && f->inode->ops->read)
        return f->inode->ops->read(f, buf, len);

    return -1;
}

/* ---- Write ---- */
int64_t vfs_write(struct file *f, const char *buf, uint64_t len)
{
    if (!f || !f->used || !f->inode)
        return -1;

    if ((f->flags & 0x3) == O_RDONLY)
        return -1;

    if (f->inode->ops && f->inode->ops->write)
        return f->inode->ops->write(f, buf, len);

    return -1;
}

/* ---- Close ---- */
int64_t vfs_close(struct file *f)
{
    int64_t ret = 0;

    if (!f || !f->used)
        return -1;

    if (f->inode) {
        if (f->inode->ops && f->inode->ops->close)
            ret = f->inode->ops->close(f);
        f->inode->refcount--;
        /*
         * Free the inode when no more references exist and it has
         * no directory entry (nlink == 0).  This reclaims inodes
         * used by anonymous objects such as pipes.
         */
        if (f->inode->refcount == 0 && f->inode->nlink == 0) {
            f->inode->used = 0;
            f->inode->ino = 0;
        }
    }

    f->used = 0;
    f->inode = 0;
    return ret;
}

/* ---- Create a new file ---- */
int vfs_create(const char *path, int fs_type)
{
    char parent_path[MAX_PATH_LEN];
    const char *name;
    int parent_ino;
    struct inode *inode;

    path_parent(path, parent_path, MAX_PATH_LEN);
    name = path_basename(path);

    parent_ino = vfs_lookup(parent_path);
    if (parent_ino < 0) {
        uart_puts("[VFS] ERROR: parent directory not found: ");
        uart_puts(parent_path);
        uart_puts("\n");
        return -1;
    }

    inode = vfs_alloc_inode();
    if (!inode) return -1;

    inode->type = FILE_TYPE_REGULAR;
    inode->fs_type = fs_type;
    inode->size = 0;
    inode->data = 0;
    inode->mode = DEFAULT_FILE_MODE;
    inode->nlink = 1;

    if (fs_type == FS_RAMFS) {
        extern struct file_operations ramfs_file_ops;
        inode->ops = &ramfs_file_ops;
    } else {
        inode->ops = 0;
    }

    if (vfs_add_dentry(parent_ino, inode->ino, name) < 0) {
        inode->used = 0;
        return -1;
    }

    return inode->ino;
}

/* ---- Stat ---- */
int vfs_stat(int ino, struct stat *st)
{
    struct inode *inode;

    if (!st)
        return -1;

    inode = vfs_find_inode(ino);
    if (!inode)
        return -1;

    st->st_dev = 1;  /* Device 1 = ramfs */
    st->st_ino = (uint64_t)inode->ino;
    st->st_mode = inode->mode;
    st->st_nlink = inode->nlink;
    st->st_size = inode->size;
    st->st_atime = inode->atime;
    st->st_mtime = inode->mtime;
    st->st_ctime = inode->ctime;

    return 0;
}

/* ---- Mkdir ---- */
int vfs_mkdir(const char *path)
{
    char parent_path[MAX_PATH_LEN];
    const char *name;
    int parent_ino;
    struct inode *inode;

    path_parent(path, parent_path, MAX_PATH_LEN);
    name = path_basename(path);

    parent_ino = vfs_lookup(parent_path);
    if (parent_ino < 0)
        return -1;

    /* If the path already exists, return EEXIST (-17) */
    if (vfs_lookup(path) >= 0)
        return -17;

    inode = vfs_alloc_inode();
    if (!inode) return -1;

    inode->type = FILE_TYPE_DIR;
    inode->fs_type = FS_RAMFS;
    inode->size = 0;
    inode->data = 0;
    inode->mode = DEFAULT_DIR_MODE;
    inode->nlink = 2;  /* . and parent's reference */
    inode->ops = 0;

    if (vfs_add_dentry(parent_ino, inode->ino, name) < 0) {
        inode->used = 0;
        return -1;
    }

    return inode->ino;
}

/* ---- Unlink ---- */
int vfs_unlink(const char *path)
{
    char parent_path[MAX_PATH_LEN];
    const char *name;
    int parent_ino;
    int child_ino;
    int i;

    path_parent(path, parent_path, MAX_PATH_LEN);
    name = path_basename(path);

    parent_ino = vfs_lookup(parent_path);
    if (parent_ino < 0)
        return -1;

    /* Find the dentry */
    for (i = 0; i < MAX_DENTRY; i++) {
        if (dentry_table[i].used &&
            dentry_table[i].parent_ino == parent_ino &&
            my_strcmp(dentry_table[i].name, name) == 0) {
            child_ino = dentry_table[i].child_ino;
            struct inode *inode = vfs_find_inode(child_ino);
            if (inode) {
                inode->nlink--;
                if (inode->nlink == 0) {
                    inode->used = 0;
                }
            }
            dentry_table[i].used = 0;
            return 0;
        }
    }

    return -1;
}

/*
 * getdents_ctx - state used by vfs_getdents to append entries.
 * Kept at file scope so the append helper does not need to be a
 * GCC nested function (which would rely on a non-standard extension).
 */
struct getdents_ctx {
    char    *out;     /* base of user buffer */
    uint64_t pos;     /* current write offset */
    uint64_t count;   /* total buffer size */
};

/*
 * getdents_append - write one linux_dirent entry into the buffer.
 * Returns 1 on success, 0 if there is no space left.
 */
static int getdents_append(struct getdents_ctx *ctx,
                            uint64_t ino_val, const char *name_str)
{
    int slen = my_strlen(name_str);
    uint16_t reclen = (uint16_t)(sizeof(uint64_t) + sizeof(int64_t) +
                                 sizeof(uint16_t) + slen + 1);
    reclen = (uint16_t)((reclen + 7) & ~7);  /* 8-byte align */
    if (ctx->pos + reclen > ctx->count) return 0;

    struct linux_dirent *d = (struct linux_dirent *)(ctx->out + ctx->pos);
    d->d_ino    = ino_val;
    d->d_off    = (int64_t)(ctx->pos + reclen);
    d->d_reclen = reclen;

