/*
 * ramfs.c - RAM-based file system implementation
 *
 * ramfs stores file data in physical memory pages allocated
 * via PMM.  Each file can occupy up to one page (4 KB).
 * Writes beyond the current allocation grow the file by
 * allocating a new page.  The file offset is managed by
 * the struct file in the VFS layer.
 */

#include "ramfs.h"
#include "pmm.h"
#include "defs.h"

/* ---- ramfs file operations ---- */

static int64_t ramfs_open(struct file *f)
{
    (void)f;
    return 0;
}

static int64_t ramfs_read(struct file *f, char *buf, uint64_t len)
{
    struct inode *inode = f->inode;
    uint64_t remaining;
    uint64_t i;

    if (!inode->data || f->offset >= inode->size)
        return 0;

    remaining = inode->size - f->offset;
    if (len > remaining)
        len = remaining;

    const char *src = (const char *)inode->data;
    for (i = 0; i < len; i++) {
        buf[i] = src[f->offset + i];
    }

    f->offset += len;
    return (int64_t)len;
}

static int64_t ramfs_write(struct file *f, const char *buf, uint64_t len)
{
    struct inode *inode = f->inode;
    uint64_t i;

    if (!inode->data) {
        uintptr_t page = pmm_alloc_page();
        if (page == 0) {
            uart_puts("[RAMFS] ERROR: cannot allocate data page\n");
            return -1;
        }
        inode->data = page;

        char *p = (char *)page;
        for (i = 0; i < PAGE_SIZE; i++)
            p[i] = 0;
    }

    if (f->offset + len > PAGE_SIZE)
        len = PAGE_SIZE - f->offset;

    if (len == 0)
        return 0;

    char *dst = (char *)inode->data;
    for (i = 0; i < len; i++) {
        dst[f->offset + i] = buf[i];
    }

    f->offset += len;

    if (f->offset > inode->size)
        inode->size = f->offset;

    return (int64_t)len;
}

static int64_t ramfs_close(struct file *f)
{
    (void)f;
    return 0;
}

struct file_operations ramfs_file_ops = {
    .open  = ramfs_open,
    .read  = ramfs_read,
    .write = ramfs_write,
    .close = ramfs_close,
};

/* ---- ramfs initialisation ---- */

int ramfs_init(void)
{
    struct inode *root;

    root = vfs_alloc_inode();
    if (!root) return -1;

    root->type = FILE_TYPE_DIR;
    root->fs_type = FS_RAMFS;
    root->size = 0;
    root->data = 0;
    root->ops = 0;
    root->mode = DEFAULT_DIR_MODE;
    root->nlink = 2;
    root->atime = 1;
    root->mtime = 1;
    root->ctime = 1;

    uart_puts("[RAMFS] Root directory created, ino=");
    uart_put_dec(root->ino);
    uart_puts("\n");

    return 0;
}

int ramfs_create_file(const char *name, int parent_ino)
{
    struct inode *inode;

    inode = vfs_alloc_inode();
    if (!inode) return -1;

    inode->type = FILE_TYPE_REGULAR;
    inode->fs_type = FS_RAMFS;
    inode->size = 0;
    inode->data = 0;
    inode->ops = &ramfs_file_ops;
    inode->mode = DEFAULT_FILE_MODE;
    inode->nlink = 1;
    inode->atime = 1;
    inode->mtime = 1;
    inode->ctime = 1;

    if (vfs_add_dentry(parent_ino, inode->ino, name) < 0) {
        inode->used = 0;
        return -1;
    }

    return inode->ino;
}

/*
 * ramfs_create_file_with_content - Create a file with initial content
 *
 * Allocates a data page, copies the content, and sets the file size.
 * Used to pre-populate test fixtures with real file data.
 */
int ramfs_create_file_with_content(const char *name, int parent_ino,
                                   const char *content, uint64_t size)
{
    struct inode *inode;
    uintptr_t page;
    uint64_t i;

    inode = vfs_alloc_inode();
    if (!inode) return -1;

    inode->type = FILE_TYPE_REGULAR;
    inode->fs_type = FS_RAMFS;
    inode->size = size;
    inode->ops = &ramfs_file_ops;
    inode->mode = DEFAULT_FILE_MODE;
    inode->nlink = 1;
    inode->atime = 1;
    inode->mtime = 1;
    inode->ctime = 1;

    /* Allocate a data page for the file content */
    page = pmm_alloc_page();
    if (page == 0) {
        inode->used = 0;
        return -1;
    }
    inode->data = page;

    /* Zero-fill the page first */
    char *p = (char *)page;
    for (i = 0; i < PAGE_SIZE; i++)
        p[i] = 0;

    /* Copy the content */
    for (i = 0; i < size; i++)
        p[i] = content[i];

    if (vfs_add_dentry(parent_ino, inode->ino, name) < 0) {
        inode->used = 0;
        return -1;
    }

    return inode->ino;
}

/*
 * devfs.c - Device file system implementation
 *
 * devfs exposes character devices as files under /dev.
 * Currently supported devices:
 *   /dev/console - UART serial port (read/write)
 *   /dev/null    - Null device (writes are discarded, reads return EOF)
 *
 * The device file operations dispatch to the appropriate
 * device driver based on the inode's dev_id field.
 */

#include "devfs.h"
#include "defs.h"

/* ---- UART device helpers ---- */

/*
 * uart_dev_read - Read characters from the UART
 * @f:   the open file
 * @buf: destination buffer
 * @len: maximum number of bytes to read
 *
 * Reads up to @len bytes from the UART receive buffer.
 * Currently implements a simple polling read: checks the
 * UART LSR (Line Status Register) for data-ready and
 * reads one character at a time.
 *
 * Returns the number of bytes read, or 0 if no data available.
 */
static int64_t uart_dev_read(struct file *f, char *buf, uint64_t len)
{
    uint64_t count = 0;
    (void)f;

    while (count < len) {
        /* Check if data is available in the UART RX buffer */
        if (UART_REG(UART_LSR) & 0x01) {
            /* Data ready: read the character */
            buf[count] = UART_REG(UART_THR);  /* RX register at same offset */
            count++;
        } else {
            /* No more data available */
            break;
        }
    }

    return (int64_t)count;
}

/*
 * uart_dev_write - Write characters to the UART
 * @f:   the open file
 * @buf: source buffer
 * @len: number of bytes to write
 *
 * Writes all @len bytes to the UART transmit buffer.
 * Blocks until each character has been accepted by the UART.
 *
 * Returns the number of bytes written.
 */
static int64_t uart_dev_write(struct file *f, const char *buf, uint64_t len)
{
    uint64_t i;
    (void)f;

    for (i = 0; i < len; i++) {
        uart_putc(buf[i]);
    }

    return (int64_t)len;
}

/* ---- Null device helpers ---- */

/*
 * null_dev_read - Read from /dev/null (always returns EOF)
 */
static int64_t null_dev_read(struct file *f, char *buf, uint64_t len)
{
    (void)f;
    (void)buf;
    (void)len;
    return 0;  /* EOF */
}

/*
 * null_dev_write - Write to /dev/null (discards all data)
 */
static int64_t null_dev_write(struct file *f, const char *buf, uint64_t len)
{
    (void)f;
    (void)buf;
    return (int64_t)len;  /* Pretend we wrote everything */
}

/* ---- devfs file operations ---- */

/*
 * devfs_open - Open handler for device files
 * @f: the file being opened
 *
 * No special setup needed; just return success.
 */
static int64_t devfs_open(struct file *f)
{
    (void)f;
    return 0;
}

/*
 * devfs_read - Read from a device file
 * @f:   the open file
 * @buf: destination buffer
 * @len: number of bytes to read
 *
 * Dispatches to the appropriate device driver based on
 * the inode's dev_id field.
 */
static int64_t devfs_read(struct file *f, char *buf, uint64_t len)
{
    if (!f->inode) return -1;

    switch (f->inode->dev_id) {
    case DEV_UART:
        return uart_dev_read(f, buf, len);
    case DEV_NULL:
        return null_dev_read(f, buf, len);
    default:
        return -1;
    }
}

/*
 * devfs_write - Write to a device file
 * @f:   the open file
 * @buf: source buffer
 * @len: number of bytes to write
 *
 * Dispatches to the appropriate device driver based on
 * the inode's dev_id field.
 */
static int64_t devfs_write(struct file *f, const char *buf, uint64_t len)
{
    if (!f->inode) return -1;

    switch (f->inode->dev_id) {
    case DEV_UART:
        return uart_dev_write(f, buf, len);
    case DEV_NULL:
        return null_dev_write(f, buf, len);
    default:
        return -1;
    }
}

/*
 * devfs_close - Close handler for device files
 * @f: the file being closed
 *
 * No special cleanup needed.
 */
static int64_t devfs_close(struct file *f)
{
    (void)f;
    return 0;
}

/* ---- File operations vector ---- */
struct file_operations devfs_file_ops = {
    .open  = devfs_open,
    .read  = devfs_read,
    .write = devfs_write,
    .close = devfs_close,
};

/* ---- devfs initialisation ---- */

/*
 * devfs_init - Set up the /dev directory and device files
 *
 * Creates:
 *   1. The /dev directory inode (ino=2)
 *   2. /dev/console - UART character device
 *   3. /dev/null    - Null device
 *
 * Returns 0 on success, -1 on failure.
 */
int devfs_init(void)
{
    struct inode *dev_dir;
    struct inode *console_inode;
    struct inode *null_inode;

    /* Create /dev directory */
    dev_dir = vfs_alloc_inode();
    if (!dev_dir) return -1;

    dev_dir->type = FILE_TYPE_DIR;
    dev_dir->fs_type = FS_DEVFS;
    dev_dir->size = 0;
    dev_dir->data = 0;
    dev_dir->ops = 0;
    dev_dir->mode = DEFAULT_DIR_MODE;
    dev_dir->nlink = 2;
    dev_dir->atime = 1;
    dev_dir->mtime = 1;
    dev_dir->ctime = 1;

    /* Add /dev dentry under ramfs root (ino=1) */
    vfs_add_dentry(1, dev_dir->ino, "dev");

    uart_puts("[DEVFS] /dev directory created, ino=");
    uart_put_dec(dev_dir->ino);
    uart_puts("\n");

    /* Create /dev/console (UART) */
    console_inode = vfs_alloc_inode();
    if (!console_inode) return -1;

    console_inode->type = FILE_TYPE_CHARDEV;
    console_inode->fs_type = FS_DEVFS;
    console_inode->dev_id = DEV_UART;
    console_inode->ops = &devfs_file_ops;
    console_inode->size = 0;
    console_inode->data = 0;
    console_inode->mode = 020666;  /* crw-rw-rw- */
    console_inode->nlink = 1;
    console_inode->atime = 1;
    console_inode->mtime = 1;
    console_inode->ctime = 1;

    vfs_add_dentry(dev_dir->ino, console_inode->ino, "console");

    uart_puts("[DEVFS] /dev/console (UART) created, ino=");
    uart_put_dec(console_inode->ino);
    uart_puts("\n");

    /* Create /dev/null */
    null_inode = vfs_alloc_inode();
    if (!null_inode) return -1;

    null_inode->type = FILE_TYPE_CHARDEV;
    null_inode->fs_type = FS_DEVFS;
    null_inode->dev_id = DEV_NULL;
    null_inode->ops = &devfs_file_ops;
    null_inode->size = 0;
    null_inode->data = 0;
    null_inode->mode = 020666;  /* crw-rw-rw- */
    null_inode->nlink = 1;
    null_inode->atime = 1;
    null_inode->mtime = 1;
    null_inode->ctime = 1;

    vfs_add_dentry(dev_dir->ino, null_inode->ino, "null");

    uart_puts("[DEVFS] /dev/null created, ino=");
    uart_put_dec(null_inode->ino);
    uart_puts("\n");

    return 0;
}

/*
 * elf_loader.c - ELF64 static executable loader for sys_execve
 *
 * Parses a static ELF64 file, copies PT_LOAD segments into user
 * memory at USER_CODE_BASE, and returns the entry point address.
 *
 * Supports two input formats:
 *   1. Real ELF64 executable (detected by ELF magic 0x7F 'E' 'L' 'F')
 *      - Parses Elf64_Ehdr + Elf64_Phdr
 *      - Copies PT_LOAD segments to USER_CODE_BASE
 *      - Zero-fills BSS (memsz - filesz)
 *      - Adjusts entry point relative to USER_CODE_BASE
 *
 *   2. Flat binary (no ELF magic)
 *      - Copies raw bytes to USER_CODE_BASE
 *      - Entry point = USER_CODE_BASE
 *
 * The flat-binary fallback allows loading the existing user_prog.S
 * blob (compiled into the kernel) while the ELF parser is ready
 * for future standalone ELF executables.
 */

#include "elf.h"
#include "syscall.h"
#include "defs.h"
#include "pmm.h"
#include "vmm.h"

/*
 * elf_ensure_user_page_mapped - Map USER_CODE_BASE page if not already mapped.
 *
 * Allocates a physical page and maps it at USER_CODE_BASE with
 * Read/Write/Execute permissions (NO User bit) so the S-mode loader
 * can copy the program bytes there.  After loading, elf_set_user_perms()
 * must be called to add the User bit so the CPU can execute the code
 * in user mode.
 *
 * Returns 0 on success, -1 on allocation failure.
 */
static int elf_ensure_user_page_mapped(void)
{
    uintptr_t phys = pmm_alloc_page();
    if (phys == 0)
        return -1;

    /* Zero the physical page */
    for (int i = 0; i < 1024; i++)
        ((uint64_t *)phys)[i] = 0;

    /* Map at USER_CODE_BASE with RWX permissions (NO U bit).
     * S-mode can write to this page; U-mode cannot (yet). */
    vmm_arch_map_page((uintptr_t)USER_CODE_BASE, phys,
                       VMM_FLAG_READ | VMM_FLAG_WRITE | VMM_FLAG_EXEC);
    return 0;
}

/*
 * elf_set_user_perms - Add User permission to USER_CODE_BASE page.
 *
 * Called after elf_load() has copied the program bytes.  Adds the
 * User permission bit to the PTE so the CPU can execute the code
 * in U-mode.
 */
static void elf_set_user_perms(void)
{
    vmm_arch_set_user_bit((uintptr_t)USER_CODE_BASE);
}

/*
 * elf_load_flat - Load a flat binary (no ELF header)
 *
 * Copies raw bytes to USER_CODE_BASE and sets entry = USER_CODE_BASE.
 */
static int elf_load_flat(const uint8_t *data, uint64_t size,
                          uint64_t *entry_out)
{
    char *dst = (char *)USER_CODE_BASE;
    uint64_t i;

    if (size > USER_CODE_SIZE)
        size = USER_CODE_SIZE;

    /* Ensure USER_CODE_BASE is mapped before writing */
    if (elf_ensure_user_page_mapped() != 0)
        return -1;

    for (i = 0; i < size; i++)
        dst[i] = (char)data[i];

    /* Zero-fill remaining space */
    for (; i < USER_CODE_SIZE; i++)
        dst[i] = 0;

    /* Add User permission so the code can execute in U-mode */
    elf_set_user_perms();

    *entry_out = USER_CODE_BASE;
    return 0;
}

/*
 * elf_load - Parse and load an executable into user memory
 *
 * @elf_data: pointer to the raw file bytes (ELF or flat binary)
 * @elf_size: size of the file data in bytes
 * @entry_out: output - entry point virtual address
 *
 * Returns 0 on success (with *entry_out set), -1 on failure.
 */
int elf_load(const uint8_t *elf_data, uint64_t elf_size,
              uint64_t *entry_out)
{
    const Elf64_Ehdr *ehdr;
    const Elf64_Phdr *phdr;
    const uint8_t *phdr_base;
    uint64_t entry;
    int i;
    int found_load = 0;

    if (!elf_data || !entry_out || elf_size < 4)
        return -1;

    /* ---- If not ELF magic, treat as flat binary ---- */
    if (!elf_check_magic(elf_data))
        return elf_load_flat(elf_data, elf_size, entry_out);

    /* ---- Verify 64-bit class ---- */
    if (elf_data[EI_CLASS] != ELFCLASS64)
        return -1;

    /* ---- Need at least the ELF header ---- */
    if (elf_size < sizeof(Elf64_Ehdr))
        return -1;

    ehdr = (const Elf64_Ehdr *)elf_data;

    /* ---- Verify it's an executable ---- */
    if (ehdr->e_type != ET_EXEC)
        return -1;

    /* ---- Verify program header table exists ---- */
    if (ehdr->e_phoff == 0 || ehdr->e_phnum == 0)
        return -1;

    /* ---- Verify program header entry size ---- */
    if (ehdr->e_phentsize != sizeof(Elf64_Phdr))
        return -1;

    entry = ehdr->e_entry;
    if (entry == 0)
        return -1;

    /* Ensure USER_CODE_BASE is mapped before copying segments */
    if (elf_ensure_user_page_mapped() != 0)
        return -1;

    /* ---- Iterate program headers ---- */
    phdr_base = elf_data + ehdr->e_phoff;

    for (i = 0; i < (int)ehdr->e_phnum; i++) {
        phdr = (const Elf64_Phdr *)(phdr_base + i * ehdr->e_phentsize);

        if (phdr->p_type != PT_LOAD)
            continue;

        /*
         * Copy the segment file data to USER_CODE_BASE.
         * For a single-segment static executable, p_vaddr is
         * typically the link-time load address (e.g. 0x100000).
         * We load at USER_CODE_BASE regardless.
         */
        const char *segment_src = (const char *)(elf_data + phdr->p_offset);
        char *dst = (char *)USER_CODE_BASE;
        uint64_t copy_off = 0;
        uint64_t copy_len = phdr->p_filesz;

        if (copy_len > USER_CODE_SIZE)
            copy_len = USER_CODE_SIZE;

        while (copy_len > 0) {
            dst[copy_off] = segment_src[copy_off];
            copy_off++;
            copy_len--;
        }

        /* Zero-fill BSS: (p_memsz - p_filesz) bytes after file data */
        while (copy_off < phdr->p_memsz && copy_off < USER_CODE_SIZE) {
            dst[copy_off] = 0;
            copy_off++;
        }

        found_load = 1;

        /*
         * Adjust the entry point to point to USER_CODE_BASE
         * (since we load there, not at the link-time address).
         */
        if (entry >= phdr->p_vaddr &&
            entry < phdr->p_vaddr + phdr->p_memsz) {
            entry = USER_CODE_BASE + (entry - phdr->p_vaddr);
        }
    }

    if (!found_load)
        return -1;

    /* Add User permission so the code can execute in U-mode */
    elf_set_user_perms();

    *entry_out = entry;
    return 0;
}

