/* ---- Mount table (real mount tracking) ---- */
#define MAX_MOUNTS 8
struct mount_entry {
    int used;                            /* 1 if this slot is in use */
    char source[MAX_PATH_LEN];           /* Source device path */
    char target[MAX_PATH_LEN];           /* Mount point path */
    char fstype[MAX_FS_NAME];            /* File system type name */
};
static struct mount_entry mount_table[MAX_MOUNTS];

/* ---- Find a mount entry by target path ---- */
static struct mount_entry *mount_find(const char *target)
{
    int i;
    if (!target) return 0;
    for (i = 0; i < MAX_MOUNTS; i++) {
        if (mount_table[i].used) {
            int j = 0;
            while (mount_table[i].target[j] && target[j] &&
                   mount_table[i].target[j] == target[j])
                j++;
            if (mount_table[i].target[j] == '\0' && target[j] == '\0')
                return &mount_table[i];
        }
    }
    return 0;
}

/* ---- Find a free mount slot ---- */
static struct mount_entry *mount_alloc_slot(void)
{
    int i;
    for (i = 0; i < MAX_MOUNTS; i++) {
        if (!mount_table[i].used)
            return &mount_table[i];
    }
    return 0;
}

/* ---- Copy string (kernel has no libc) ---- */
static void kstrcpy(char *dst, const char *src)
{
    while (*src) *dst++ = *src++;
    *dst = '\0';
}

