static int64_t sys_write(uint64_t fd, const char *buf, uint64_t len)
{
    struct proc *p = proc_current();

    if (p && fd < MAX_FDS && p->fds[fd]) {
        return vfs_write(p->fds[fd], buf, len);
    }

    if (fd == 1 || fd == 2) {
        uint64_t i;
        for (i = 0; i < len; i++) {
            uart_putc(buf[i]);
        }
        return (int64_t)len;
    }

    return -1;
}

static int64_t sys_getpid(void)
{
    struct proc *p = proc_current();
    return p ? p->pid : -1;
}

static int64_t sys_yield(void)
{
    proc_yield();
    return 0;
}

static int64_t sys_exit(int64_t code)
{
    proc_exit_code((int)code);
    return 0;
}

static int64_t sys_open(const char *path, uint64_t flags)
{
    struct proc *p = proc_current();
    struct file *f;
    int fd;

    if (!p) return -1;

    /*
     * Resolve relative paths against the process cwd so that
     * sys_open("text.txt") works when the cwd is "/".
     * vfs_open only understands absolute paths via vfs_lookup.
     */
    if (path && path[0] != '/') {
        char full[MAX_PATH_LEN];
        char cwd_path[MAX_PATH_LEN];
