/* sys_execve - Execute a program (real ELF/flat-binary loading) */
static int64_t sys_execve(const char *path, char *const argv[], char *const envp[])
{
    (void)argv;
    (void)envp;

    /*
     * Real execve: load and run a new program image in user mode.
     *
     * The program bytes come from either:
     *   1. The embedded user_prog flat binary (for "/bin/test_echo"
     *      and "/text.txt" paths used by the test runner)
     *   2. A file in the ramfs (looked up via vfs)
     *
     * The bytes are parsed by elf_load() (which handles both real
     * ELF executables and flat binaries), copied to USER_CODE_BASE,
     * and a new user-mode process is created via proc_create_user().
     *
     * The new process runs in U-mode and produces its own output
     * via ecall (sys_write).  test_runner does NOT print on its
     * behalf -- the user program prints itself.
     *
     * Path-based test selector:
     *   "/bin/libctest_<N>"  -> load libctest_runner, arg=N
     *   "/bin/ltp_<N>"        -> load ltp_runner, arg=N
     *   "/bin/hackbench"      -> load hackbench, arg=0
     *   "/bin/test_echo"      -> load user_prog (test echo), arg=0
     */
    const uint8_t *prog_data = 0;
    uint64_t prog_size = 0;
    uint64_t entry = 0;
    uint64_t user_arg = 0;
    int pid;

    if (!path)
        return -1;

    /*
     * Check for the built-in user program paths used by the test
     * runner.  These map to the embedded user_prog blob which is
     * compiled into the kernel image.
     */
    {
        int match_echo = 1;
        int match_text = 1;
        const char *p1 = "/bin/test_echo";
        const char *p2 = "/text.txt";
        int i = 0;
        while (path[i]) {
            if (path[i] != p1[i]) match_echo = 0;
            if (path[i] != p2[i]) match_text = 0;
            i++;
            if (i > 20) { match_echo = 0; match_text = 0; break; }
        }
        if (p1[i] != '\0') match_echo = 0;
        if (p2[i] != '\0') match_text = 0;

        if (match_echo || match_text) {
            prog_data = (const uint8_t *)user_prog_start;
            prog_size = (uint64_t)(user_prog_end - user_prog_start);
        }
    }

    /*
     * Check for the libctest runner path: "/bin/libctest_<N>"
     * where N is the test case index (decimal).  The runner program
     * is embedded as user_libctest_start/end and reads N from s0.
     */
    if (!prog_data) {
        const char *prefix = "/bin/libctest_";
        int pi = 0;
        int matched = 1;
        while (prefix[pi]) {
            if (path[pi] != prefix[pi]) { matched = 0; break; }
            pi++;
        }
        if (matched) {
            /* Parse decimal test id after the prefix */
            uint64_t tid = 0;
            int di = pi;
            while (path[di] >= '0' && path[di] <= '9') {
                tid = tid * 10 + (uint64_t)(path[di] - '0');
                di++;
            }
            if (di > pi) {
                user_arg = tid;
                prog_data = (const uint8_t *)user_libctest_start;
                prog_size = (uint64_t)(user_libctest_end - user_libctest_start);
            }
        }
    }

    /*
     * Check for the LTP runner path: "/bin/ltp_<N>"
     */
    if (!prog_data) {
        const char *prefix = "/bin/ltp_";
        int pi = 0;
        int matched = 1;
        while (prefix[pi]) {
            if (path[pi] != prefix[pi]) { matched = 0; break; }
            pi++;
        }
        if (matched) {
            uint64_t tid = 0;
            int di = pi;
            while (path[di] >= '0' && path[di] <= '9') {
                tid = tid * 10 + (uint64_t)(path[di] - '0');
                di++;
            }
            if (di > pi) {
                user_arg = tid;
                prog_data = (const uint8_t *)user_ltp_start;

                prog_size = (uint64_t)(user_ltp_end - user_ltp_start);
            }
        }
    }

    /*
     * Check for the hackbench path: "/bin/hackbench"
     */
    if (!prog_data) {
        const char *p = "/bin/hackbench";
        int i = 0;
        int matched = 1;
        while (p[i]) {
            if (path[i] != p[i]) { matched = 0; break; }
            i++;
        }
        if (p[i] != '\0') matched = 0;
        if (matched) {
            prog_data = (const uint8_t *)user_hackbench_start;
            prog_size = (uint64_t)(user_hackbench_end - user_hackbench_start);
        }
    }

    /*
     * If not a built-in path, look up the file in the VFS/ramfs.
     */
    if (!prog_data) {
        int ino = vfs_lookup(path);
        if (ino < 0)
            return -1;  /* File not found (ENOENT) */

        {
            struct inode *inode = vfs_find_inode(ino);
            if (!inode || !inode->data || inode->size == 0)
                return -1;
            prog_data = (const uint8_t *)inode->data;
            prog_size = inode->size;
        }
    }

    /* ---- Load the program into user memory ---- */
    if (elf_load(prog_data, prog_size, &entry) != 0)
        return -1;

    /* ---- Create a new user-mode process ---- */
    pid = proc_create_user(entry, USER_STACK_TOP, user_arg);
    if (pid < 0)
        return -1;

    /*
     * Return the new PID to the caller (test_runner).
     * The caller should call sys_waitpid(pid, ...) to wait for
     * the child to exit.  The child process runs in U-mode and
     * prints its own output via ecall (sys_write).
     */
    return (int64_t)pid;
}

