        return -1;

    /*
     * Validate that both source and target paths resolve in the VFS.
     * A real mount would bind the source filesystem at the target
     * directory; we record the mount in the mount table so that
     * umount can report real success/failure.
     */
    int src_ino = vfs_lookup(source);
    int tgt_ino = vfs_lookup(target);
    if (src_ino < 0 && tgt_ino < 0)
        return -1;  /* Neither path exists */

    /* Reject duplicate mount on the same target */
    if (mount_find(target))
        return -1;  /* Already mounted (EBUSY) */

    slot = mount_alloc_slot();
    if (!slot)
        return -1;  /* Mount table full (ENODEV) */

    slot->used = 1;
    kstrcpy(slot->source, source);
    kstrcpy(slot->target, target);
    if (fstype)
        kstrcpy(slot->fstype, fstype);
    else
        slot->fstype[0] = '\0';

    return 0;
}

