/* sys_sleep - Sleep for a number of seconds (real busy-wait on timer) */
static int64_t sys_sleep(uint64_t seconds)
{
    uint64_t start, now, target_ticks;

    if (seconds == 0) {
        proc_yield();
        return 0;
    }

    /*
     * Busy-wait on the real hardware timer until the requested
     * number of seconds has elapsed.  RISC-V timer runs at 10 MHz,
     * LoongArch at 100 MHz, so we compute the target tick count
     * accordingly.
     */
    start = timer_get_ticks();
#ifdef __loongarch__
    target_ticks = seconds * 100000000ULL;
#else
    target_ticks = seconds * 10000000ULL;
#endif

    do {
        now = timer_get_ticks();
        /* Yield to scheduler periodically so other processes can run */
        if ((now - start) % (target_ticks / (seconds * 10 + 1) + 1) == 0)
            proc_yield();
    } while (now - start < target_ticks);

    return 0;
}

/* sys_times - Get process times (real tick counts from scheduler) */
static int64_t sys_times(struct tms *buf)
{
    struct proc *p = proc_current();
    uint64_t now;

    if (!buf)
        return -1;

    /*
     * tms_utime: user CPU time (ticks accumulated by this process)
     * tms_stime: system CPU time (approximated as boot_tick counter
     *            minus user time, since we don't have separate
     *            kernel/user tick tracking)
     * tms_cutime/cstime: children CPU time (not tracked separately)
     */
    now = timer_get_ticks();
    buf->tms_utime = p ? p->total_ticks : 0;
    buf->tms_stime = p ? (now / 10000 - p->total_ticks) : 0;
    buf->tms_cutime = 0;
    buf->tms_cstime = 0;

    return (int64_t)now;
}

