        return -1;  /* Cannot install a handler for SIGKILL */

    /* Save old handler if requested */
    if (oldact) {
        oldact->sa_handler = p->signal_handlers[signum];
        oldact->sa_flags = 0;
        oldact->sa_mask = 0;
