/*
 * syscall_handler - Dispatch a system call with 3 arguments
 */
int64_t syscall_handler(uint64_t num, uint64_t a0, uint64_t a1, uint64_t a2)
{
    switch (num) {
    case SYS_write:        return sys_write(a0, (const char *)a1, a2);
    case SYS_getpid:       return sys_getpid();
    case SYS_yield:        return sys_yield();
    case SYS_exit:         return sys_exit((int64_t)a0);
    case SYS_open:         return sys_open((const char *)a0, a1);
    case SYS_read:         return sys_read(a0, (char *)a1, a2);
    case SYS_close:        return sys_close(a0);
    case SYS_brk:          return sys_brk(a0);
    case SYS_chdir:        return sys_chdir((const char *)a0);
    case SYS_clone:        return sys_clone(a0, a1);
    case SYS_dup:          return sys_dup(a0);
    case SYS_dup2:         return sys_dup2(a0, a1);
    case SYS_execve:       return sys_execve((const char *)a0, (char *const *)a1, (char *const *)a2);
    case SYS_fork:         return sys_fork();
    case SYS_fstat:        return sys_fstat(a0, (struct stat *)a1);
    case SYS_getcwd:       return sys_getcwd((char *)a0, a1);
    case SYS_getdents:     return sys_getdents(a0, (void *)a1, a2);
    case SYS_getppid:      return sys_getppid();
    case SYS_gettimeofday: return sys_gettimeofday((struct timeval *)a0, (void *)a1);
    case SYS_mkdir:        return sys_mkdir((const char *)a0, a1);
    case SYS_mount:        return sys_mount((const char *)a0, (const char *)a1, (const char *)a2, 0, 0);
    case SYS_munmap:       return sys_munmap(a0, a1);
    case SYS_openat:       return sys_openat(a0, (const char *)a1, a2);
    case SYS_pipe:         return sys_pipe((int *)a0);
    case SYS_sleep:        return sys_sleep(a0);
    case SYS_times:         return sys_times((struct tms *)a0);
    case SYS_umount:       return sys_umount((const char *)a0);
    case SYS_uname:        return sys_uname((struct utsname *)a0);
    case SYS_unlink:       return sys_unlink((const char *)a0);
    case SYS_wait:         return sys_wait((int *)a0);
    case SYS_waitpid:      return sys_waitpid((int64_t)a0, (int *)a1, (int64_t)a2);
    case SYS_sigaction:    return sys_sigaction((int)a0, (const struct sigaction *)a1, (struct sigaction *)a2);
    case SYS_sigreturn:    return sys_sigreturn();
    case SYS_kill:         return sys_kill((int)a0, (int)a1);
    case SYS_mprotect:    return sys_mprotect(a0, a1, (int)a2);
    default:
        uart_puts("[SYSCALL] ERROR: unknown syscall ");
        uart_put_dec(num);
        uart_puts("\n");
        return -1;
    }
}

/*
 * syscall_handler6 - Dispatch a system call with 6 arguments
 */
int64_t syscall_handler6(uint64_t num, uint64_t a0, uint64_t a1, uint64_t a2,
                          uint64_t a3, uint64_t a4, uint64_t a5)
