/*
 * vmm.c - RISC-V 64-bit virtual memory (Sv39) implementation
 *
 * Implements 3-level Sv39 page table operations:
 *   - vmm_arch_init:      allocate root page table
 *   - vmm_arch_map_page:  insert a mapping
 *   - vmm_arch_enable:    set satp and enable paging
 */

#include "vmm.h"
#include "pmm.h"
#include "defs.h"
#include "mmu.h"

/* Root page table physical address */
static uintptr_t root_pt_phys;

/* ---- Helper: walk the page table and return PTE pointer ---- */

/*
 * walk_pt - Walk the 3-level page table for a given virtual address
 *
 * Returns a pointer to the leaf PTE.  If intermediate page tables
 * do not exist, they are allocated from the PMM.
 *
 * Returns 0 on allocation failure.
 */
static uint64_t *walk_pt(uintptr_t vaddr)
{
    uint64_t vpn[3];
    uint64_t *pt;
    int level;

    /* Extract the three VPN fields */
    vpn[2] = (vaddr >> 30) & SV39_VPN_MASK;  /* bits [38:30] */
    vpn[1] = (vaddr >> 21) & SV39_VPN_MASK;  /* bits [29:21] */
    vpn[0] = (vaddr >> 12) & SV39_VPN_MASK;  /* bits [20:12] */

    pt = (uint64_t *)root_pt_phys;

    for (level = 2; level > 0; level--) {
        uint64_t pte = pt[vpn[level]];

        if (pte & PTE_V) {
            /* PTE is valid, follow the pointer */
            pt = (uint64_t *)PPN_TO_PA(PTE_PPN(pte));
        } else {
            /* Allocate a new page table page */
            uintptr_t new_pt = pmm_alloc_page();
            if (new_pt == 0)
                return 0;

            /* Zero the new page table */
            for (int i = 0; i < SV39_PTES_PER_PT; i++)
                ((uint64_t *)new_pt)[i] = 0;

            /* Install the PTE pointing to the new page table */
            pt[vpn[level]] = PTE_FROM_PPN(PA_TO_PPN(new_pt), PTE_V);
            pt = (uint64_t *)new_pt;
        }
    }

    /* Return pointer to the leaf PTE */
    return &pt[vpn[0]];
}

/* ---- Public architecture-specific API ---- */

void vmm_arch_init(void)
{
    /* Allocate the root (level-2) page table */
    root_pt_phys = pmm_alloc_page();
    if (root_pt_phys == 0) {
        uart_puts("[VMM] FATAL: cannot allocate root page table\n");
        while (1) ;
    }

    /* Zero the root page table */
    for (int i = 0; i < SV39_PTES_PER_PT; i++)
        ((uint64_t *)root_pt_phys)[i] = 0;

    uart_puts("[VMM] Root page table at ");
    uart_put_hex(root_pt_phys);
    uart_puts("\n");
}

void vmm_arch_map_page(uintptr_t vaddr, uintptr_t paddr, uint64_t flags)
{
    uint64_t *pte = walk_pt(vaddr);
    if (pte == 0) {
        uart_puts("[VMM] FATAL: walk_pt failed for vaddr ");
        uart_put_hex(vaddr);
        uart_puts("\n");
        while (1) ;
    }

    /* Translate generic flags to RISC-V PTE flags */
    uint64_t pte_flags = PTE_A | PTE_D;  /* always set Accessed & Dirty */
    if (flags & VMM_FLAG_READ)  pte_flags |= PTE_R;
    if (flags & VMM_FLAG_WRITE) pte_flags |= PTE_W;
    if (flags & VMM_FLAG_EXEC)  pte_flags |= PTE_X;
    if (flags & VMM_FLAG_USER)  pte_flags |= PTE_U;

    /* Write the leaf PTE */
    *pte = PTE_FROM_PPN(PA_TO_PPN(paddr), pte_flags | PTE_V);

    /*
     * Flush the TLB so the new mapping takes effect immediately.
     * This is critical when remapping a virtual address that already
     * has a stale TLB entry pointing to an old physical page;
     * without flushing, subsequent S-mode writes would go to the
     * old page while U-mode reads (after TLB flush elsewhere) would
     * see the new (zeroed) page — causing "Illegal instruction".
     */
    sfence_vma();
}

void vmm_arch_enable(void)
{
    /* Set satp to Sv39 mode with the root page table PPN */
    uint64_t satp_val = SATP_MODE_SV39 | PA_TO_PPN(root_pt_phys);
    csr_write(satp, satp_val);

    /* Flush the TLB */
    sfence_vma();
}

uintptr_t vmm_get_root(void)
{
    return root_pt_phys;
}

/*
 * vmm_arch_protect_page - Change protection of a mapped page (RISC-V Sv39)
 *
 * Walks the 3-level page table, finds the leaf PTE for the page
 * containing @vaddr, and updates its R/W/X permission bits while
 * preserving the PPN and other flags (V, U, A, D).
 *
 * After updating the PTE, flushes the TLB via sfence.vma so the
 * new permissions take effect immediately.
 *
 * Returns 0 on success, -1 if the page is not mapped.
 */
int vmm_arch_protect_page(uintptr_t vaddr, int prot)
{
    uint64_t *pte;
    uint64_t old_pte;
    uint64_t ppn;
    uint64_t new_flags = PTE_A | PTE_D | PTE_V;  /* keep V, A, D */

    /* Page-align the address */
    vaddr &= ~0xFFFUL;

    pte = walk_pt(vaddr);
    if (pte == 0)
        return -1;

    old_pte = *pte;
    if (!(old_pte & PTE_V))
        return -1;  /* Page not mapped */

    /* Preserve the PPN and U flag */
    ppn = PTE_PPN(old_pte);
    if (old_pte & PTE_U)
        new_flags |= PTE_U;

    /* Set new permission flags */
    if (prot & 1)  new_flags |= PTE_R;  /* PROT_READ */
    if (prot & 2)  new_flags |= PTE_W;  /* PROT_WRITE */
    if (prot & 4)  new_flags |= PTE_X;  /* PROT_EXEC */
    /* PROT_NONE (prot == 0): no R/W/X bits, page is inaccessible */

    /* Write the updated PTE */
    *pte = PTE_FROM_PPN(ppn, new_flags);

    /* Flush TLB so new permissions take effect */
    sfence_vma();

    return 0;
}

/*
 * vmm_arch_set_user_bit - Add the User permission bit to a mapped page
 * (RISC-V Sv39)
 *
 * Walks the page table, finds the leaf PTE for the page containing
 * @vaddr, and adds the PTE_U flag while preserving all other bits
 * (PPN, V, A, D, R, W, X).  Flushes the TLB afterwards.
 *
 * This is used by the ELF loader to add U permission after loading
 * a program in S-mode (where the page was mapped without U so S-mode
 * could write to it).
 *
 * Returns 0 on success, -1 if the page is not mapped.
 */
int vmm_arch_set_user_bit(uintptr_t vaddr)
{
    uint64_t *pte;

    /* Page-align the address */
    vaddr &= ~0xFFFUL;

    pte = walk_pt(vaddr);
    if (pte == 0)
        return -1;

    if (!(*pte & PTE_V))
        return -1;  /* Page not mapped */

    /* Add the User permission bit, preserving everything else */
    *pte |= PTE_U;

    /* Flush TLB so the new permission takes effect */
    sfence_vma();

    return 0;
}

/*
 * sched.c - RISC-V 64-bit scheduler and timer support
 *
 * Implements timer_enable() and timer_reset() using the
 * SBI (Supervisor Binary Interface) ecall to set the timer.
 * This avoids direct CLINT MMIO access which requires
 * page-table mappings that may not be set up correctly.
 *
 * SBI v0.1 (legacy) provides sbi_set_timer() as ecall with
 * extension ID 0x0 and function ID 0x0.
 *
 * SBI v1.0 uses the base extension:
 *   ecall with a6=0x54494D45 ("TIME"), a7=0x0 (Set Timer)
 */

#include "sched.h"
#include "proc.h"
#include "defs.h"
#include "mmu.h"

/* Timer tick frequency: ~10 ms per tick (assuming 10 MHz clock) */
#define TIMER_INTERVAL  100000UL

/* ---- SBI ecall for setting the timer ---- */
static inline void sbi_set_timer(uint64_t stime_value)
{
    /*
     * Use the legacy SBI set_timer call:
     *   a0 = stime_value (time at which the next interrupt should fire)
     *   a7 = 0x0 (extension ID for set_timer in legacy SBI)
     *
     * In OpenSBI (which QEMU virt uses), this is the standard way
     * to program the timer from S-mode without direct CLINT access.
     */
    register uint64_t a0 asm("a0") = stime_value;
    register uint64_t a7 asm("a7") = 0;
    asm volatile("ecall"
                 : "+r"(a0)
                 : "r"(a7)
                 : "memory");
}

/* ---- Read the time CSR (rdtime) ---- */
static inline uint64_t rdtime(void)
{
    uint64_t time;
    asm volatile("rdtime %0" : "=r"(time));
    return time;
}

/* ---- Timer API ---- */

void timer_enable(void)
{
    /*
     * 1. Set the first mtimecmp to fire after TIMER_INTERVAL ticks
     *    using the SBI ecall.
     * 2. Enable the supervisor timer interrupt via sie.STIE.
     * 3. Enable global interrupts via sstatus.SIE.
     */

    /* Set the timer using SBI */
    uint64_t now = rdtime();
    sbi_set_timer(now + TIMER_INTERVAL);

    /* Enable supervisor timer interrupt */
    csr_set(sie, (1UL << 5));   /* STIE bit */

    /* Enable interrupts in sstatus */
    csr_set(sstatus, (1UL << 1));  /* SIE bit */

    uart_puts("[TIMER] RISC-V timer enabled via SBI, interval=");
    uart_put_dec(TIMER_INTERVAL);
    uart_puts("\n");
}

void timer_reset(void)
{
    /* Set the next timer using SBI */
    uint64_t now = rdtime();
    sbi_set_timer(now + TIMER_INTERVAL);
}

/*
 * sched_cooperative_tick - Not used on RISC-V (timer interrupts work)
 *
 * Provided for link compatibility; RISC-V uses preemptive scheduling.
 */
void sched_cooperative_tick(void)
{
    /* On RISC-V, we use timer-driven preemptive scheduling instead */
    proc_yield();
}

/*
 * timer_get_ticks - Read the RISC-V time CSR (rdtime)
 *
 * The time CSR increments at a constant frequency (10 MHz on QEMU virt),
 * providing a high-resolution monotonic counter for benchmark timing.
 */
uint64_t timer_get_ticks(void)
{
    uint64_t time;
    asm volatile("rdtime %0" : "=r"(time));
    return time;
}

