/*
 * vmm.c - LoongArch 64-bit virtual memory implementation
 *
 * Implements 3-level page table operations for LoongArch
 * with 4 KB pages and 9-bit indices per level.
 *
 *   - vmm_arch_init:      allocate root page table
 *   - vmm_arch_map_page:  insert a mapping
 *   - vmm_arch_enable:    configure PWCL/PWCH, set PGD, enable paging
 */

#include "vmm.h"
#include "pmm.h"
#include "defs.h"
#include "mmu.h"
#include "trap.h"

/* Root page table physical address */
static uintptr_t root_pt_phys;

/* ---- Helper: walk the page table and return PTE pointer ---- */

/*
 * walk_pt - Walk the 3-level page table for a given virtual address
 *
 * Returns a pointer to the leaf PTE.  If intermediate page tables
 * do not exist, they are allocated from the PMM.
 *
 * Returns 0 on allocation failure.
 */
static uint64_t *walk_pt(uintptr_t vaddr)
{
    uint64_t vpn[3];
    uint64_t *pt;
    int level;

    /* Extract the three VPN fields (9 bits each) */
    vpn[2] = (vaddr >> 30) & LA_VPN_MASK;  /* bits [38:30] */
    vpn[1] = (vaddr >> 21) & LA_VPN_MASK;  /* bits [29:21] */
    vpn[0] = (vaddr >> 12) & LA_VPN_MASK;  /* bits [20:12] */

    pt = (uint64_t *)root_pt_phys;

    for (level = 2; level > 0; level--) {
        uint64_t pte = pt[vpn[level]];

        if (pte & LA_PTE_V) {
            /* PTE is valid, follow the pointer */
            pt = (uint64_t *)(LA_PTE_PPN(pte));
        } else {
            /* Allocate a new page table page */
            uintptr_t new_pt = pmm_alloc_page();
            if (new_pt == 0)
                return 0;

            /* Zero the new page table */
            for (int i = 0; i < LA_PTES_PER_PT; i++)
                ((uint64_t *)new_pt)[i] = 0;

            /* Install the PTE pointing to the new page table */
            pt[vpn[level]] = LA_PTE_FROM_PA(new_pt, LA_PTE_V);
            pt = (uint64_t *)new_pt;
        }
    }

    /* Return pointer to the leaf PTE */
    return &pt[vpn[0]];
}

/* ---- Public architecture-specific API ---- */

void vmm_arch_init(void)
{
    /* Allocate the root (level-2) page table */
    root_pt_phys = pmm_alloc_page();
    if (root_pt_phys == 0) {
        uart_puts("[VMM] FATAL: cannot allocate root page table\n");
        while (1) ;
    }

    /* Zero the root page table */
    for (int i = 0; i < LA_PTES_PER_PT; i++)
        ((uint64_t *)root_pt_phys)[i] = 0;

    uart_puts("[VMM] Root page table at ");
    uart_put_hex(root_pt_phys);
    uart_puts("\n");
}

void vmm_arch_map_page(uintptr_t vaddr, uintptr_t paddr, uint64_t flags)
{
    uint64_t *pte = walk_pt(vaddr);
    if (pte == 0) {
        uart_puts("[VMM] FATAL: walk_pt failed for vaddr ");
        uart_put_hex(vaddr);
        uart_puts("\n");
        while (1) ;
    }

    /* Translate generic flags to LoongArch PTE flags */
    uint64_t pte_flags = LA_PTE_D;  /* always set Dirty */
    if (flags & VMM_FLAG_READ)  pte_flags |= LA_PTE_R;
    if (flags & VMM_FLAG_WRITE) pte_flags |= LA_PTE_W;
    if (flags & VMM_FLAG_EXEC)  pte_flags |= LA_PTE_X;

    /*
     * Set the PLV (Privilege Level) field in the PTE.
     * PLV=0 means only PLV0 (kernel) can access the page.
     * PLV=3 means PLV0-3 (kernel + user) can access the page.
     * The PLV field occupies PTE bits [3:2].
     */
    if (flags & VMM_FLAG_USER) {
        pte_flags |= (3UL << LA_PTE_PLV_SHIFT);  /* PLV=3: allow user access */
    }

    /* Write the leaf PTE */
    *pte = LA_PTE_FROM_PA(paddr, pte_flags | LA_PTE_V);

    /*
     * Flush the TLB so the new mapping takes effect immediately.
     * Required when remapping a virtual address that already has a
     * stale TLB entry pointing to an old physical page.
     */
    tlb_flush_all();
}

void vmm_arch_enable(void)
{
    /*
     * LoongArch uses TLB-based address translation, NOT hardware
     * page-table walking.  When paging is enabled (DA=0, PG=1),
     * the CPU first checks DMW (Direct Mapping Windows) for a
     * direct virtual-to-physical mapping, then falls back to TLB
     * lookup.  Without any DMW window or TLB entry, every memory
     * access triggers a TLB-refill exception and the CPU hangs.
     *
     * We solve this by configuring DMW0 to identity-map the entire
     * low address segment (VSEG=0).  In LA64 the DMW VSEG field
     * occupies bits [63:60]; when the top 4 bits of a virtual
     * address equal the DMW's VSEG, the address is translated
     * directly: physical = virtual & VIRT_MASK (identity mapping).
     *
     * All our addresses (RAM at 0x0, kernel at 0x200000, UART at
     * 0x1FE00000) have top 4 bits = 0, so a single DMW0 with
     * VSEG=0 covers everything.
     */

    /* ---- Step 1: Configure DMW0 for identity mapping ---- */
    uint64_t dmw0 = 0;
    dmw0 |= DMW_PLV0;                          /* PLV0 (kernel) access */
    dmw0 |= DMW_PLV3;                          /* PLV3 (user) access - needed for user mode */
    dmw0 |= (DMW_MAT_CC << DMW_MAT_SHIFT);     /* Coherent (cached) */
    dmw0 |= (0UL << DMW_VSEG_SHIFT_64);        /* VSEG = 0 */

    uart_puts("[VMM] Setting DMW0=");
    uart_put_hex(dmw0);
    uart_puts("\n");
    csr_write(0x180, dmw0);  /* CSR_DMW0 */

    /*
     * ---- Step 2: Configure PWCL / PWCH for page-table walk ----
     *
     * These registers describe the page-table layout so that a
     * software TLB-refill handler can walk the page tables.
     * They are NOT used for hardware page-table walking (LoongArch
     * does not have that).  We set them up now for future use.
     *
     * CSR_PWCL bit fields (LoongArch Architecture Spec v1.10,
     * matches Linux kernel and QEMU definitions):
     *   [4:0]   PTBASE     - Page Table base shift
     *   [9:5]   PTWIDTH    - Page Table index width
     *   [14:10] DIR1_BASE  - Directory level 1 base
     *   [19:15] DIR1_WIDTH - Directory level 1 index width
     *   [24:20] DIR2_BASE  - Directory level 2 base
     *   [29:25] DIR2_WIDTH - Directory level 2 index width
     *   [31:30] PTEWIDTH   - PTE size (0=4B, 1=8B, 2=16B)
     *
     * For a 3-level page table with 4 KB pages and 9-bit indices:
     *   PTBASE = 12, PTWIDTH = 9
     *   DIR1_BASE = 21, DIR1_WIDTH = 9
     *   DIR2_BASE = 30, DIR2_WIDTH = 9
     *   PTEWIDTH = 1 (8-byte PTEs for LA64)
     */
    uint64_t pwcl = 0;
    pwcl |= (12UL << 0);    /* PTBASE = 12 */
    pwcl |= (9UL  << 5);    /* PTWIDTH = 9 */
    pwcl |= (21UL << 10);   /* DIR1_BASE = 21 */
    pwcl |= (9UL  << 15);   /* DIR1_WIDTH = 9 */
    pwcl |= (30UL << 20);   /* DIR2_BASE = 30 */
    pwcl |= (9UL  << 25);   /* DIR2_WIDTH = 9 */
    pwcl |= (1UL  << 30);   /* PTEWIDTH = 1 (8-byte PTEs) */

    uart_puts("[VMM] Setting PWCL=");
    uart_put_hex(pwcl);
    uart_puts("\n");
    csr_write(0x1C, pwcl);  /* CSR_PWCL */

    /* PWCH: Dir3/Dir4 not used for 3-level, set to 0 */
    csr_write(0x1D, 0UL);   /* CSR_PWCH */

    /* ---- Step 3: Set the Page Global Directory base address ---- */
    uart_puts("[VMM] Setting PGD=");
    uart_put_hex(root_pt_phys);
    uart_puts("\n");
    csr_write(0x19, root_pt_phys & 0xFFFFFFFFUL);  /* CSR_PGDL */
    csr_write(0x1A, (root_pt_phys >> 32) & 0xFFFFFUL);  /* CSR_PGDH */

    /* ---- Step 4: Flush the TLB ---- */
    uart_puts("[VMM] Flushing TLB...\n");
    tlb_flush_all();

    /*
     * ---- Step 5: Set EENTRY before enabling paging ----
     *
     * Any exception triggered during the paging transition
     * (or afterwards) will jump to this address.
     */
    extern void trap_entry(void);
    csr_write(0xC, (uint64_t)trap_entry);  /* CSR_EENTRY */

    /*
     * ---- Step 6: Enable paging ----
     *
     * Set PG=1, clear DA=0 in CRMD.  Because DMW0 is already
     * configured, all subsequent address translations will go
     * through the DMW identity mapping — no TLB entries needed.
     */
    uint64_t crmd = csr_read(0x0);  /* CSR_CRMD */
    uart_puts("[VMM] Current CRMD=");
    uart_put_hex(crmd);
    uart_puts("\n");

    crmd &= ~CRMD_DA;    /* Clear DA bit */
    crmd |= CRMD_PG;     /* Set PG b

