/*
 * vmm_arch_protect_page - Change protection of a mapped page (LoongArch)
 *
 * Walks the 3-level page table and updates the PTE R/W/X bits.
 *
 * NOTE: LoongArch uses DMW (Direct Mapping Window) for identity-mapped
 * addresses (top 4 bits = 0), which bypass the page table.  For addresses
 * in the DMW range, changing the PTE does NOT change the effective
 * permissions because DMW translation takes priority.  This function
 * still updates the PTE so that TLB-based lookups (if any) will see the
 * new permissions.  After updating, it flushes the TLB.
 *
 * Returns 0 on success, -1 if the page is not mapped.
 */
int vmm_arch_protect_page(uintptr_t vaddr, int prot)
{
    uint64_t *pte;
    uint64_t old_pte;
    uint64_t ppn;
    uint64_t plv_flags;
    uint64_t new_flags = LA_PTE_D | LA_PTE_V;

    /* Page-align the address */
    vaddr &= ~0xFFFUL;

    pte = walk_pt(vaddr);
    if (pte == 0)
        return -1;

    old_pte = *pte;
    if (!(old_pte & LA_PTE_V))
        return -1;  /* Page not mapped */

    /* Preserve the PPN and PLV field */
    ppn = LA_PTE_PPN(old_pte);
    plv_flags = old_pte & (LA_PTE_PLV_MASK << LA_PTE_PLV_SHIFT);

    /* Set new permission flags */
    if (prot & 1)  new_flags |= LA_PTE_R;  /* PROT_READ */
    if (prot & 2)  new_flags |= LA_PTE_W;  /* PROT_WRITE */
    if (prot & 4)  new_flags |= LA_PTE_X;  /* PROT_EXEC */
    /* PROT_NONE: no R/W/X bits */

    new_flags |= plv_flags;

    /* Write the updated PTE */
    *pte = LA_PTE_FROM_PA(ppn, new_flags);

    /* Flush TLB so any cached entries are invalidated */
    tlb_flush_all();

    return 0;
}

/*
 * vmm_arch_set_user_bit - Add the User (PLV3) permission bit to a page
 * (LoongArch)
 *
 * Sets the PLV field to 3 (user mode) on the PTE for @vaddr.
 * Flushes the TLB afterwards.
 *
 * Returns 0 on success, -1 if the page is not mapped.
 */
int vmm_arch_set_user_bit(uintptr_t vaddr)
{
    uint64_t *pte;
    uint64_t old_pte;
    uint64_t ppn;
    uint64_t flags;

    /* Page-align the address */
    vaddr &= ~0xFFFUL;

    pte = walk_pt(vaddr);
    if (pte == 0)
        return -1;

    old_pte = *pte;
    if (!(old_pte & LA_PTE_V))
        return -1;  /* Page not mapped */

    /* Preserve PPN and other flags, set PLV to 3 (user mode) */
    ppn = LA_PTE_PPN(old_pte);
    flags = old_pte & ~(LA_PTE_PLV_MASK << LA_PTE_PLV_SHIFT);
    flags |= (3ULL << LA_PTE_PLV_SHIFT);  /* PLV=3 for user mode */

    *pte = LA_PTE_FROM_PA(ppn, flags);

    tlb_flush_all();

    return 0;
}

/*
 * sched.c - LoongArch 64-bit scheduler and timer support
 *
 * Implements timer_enable() and timer_reset() for the LoongArch
 * constant timer (CSR TCFG / TVAL / TICLR).
 *
 * Note: The LoongArch QEMU virt platform's timer interrupt
 * routing may require additional EIOINTC/PIC setup that is
 * not yet implemented.  As a workaround, we use cooperative
 * scheduling with a busy-wait delay to simulate timer ticks.
 * The context switch and round-robin scheduler still function
 * correctly; only the preemption mechanism differs.
 */

#include "sched.h"
#include "proc.h"
#include "defs.h"
#include "mmu.h"

/* ---- Timer tick interval ---- */
#define TIMER_INTERVAL  1000000UL

/* ---- LoongArch timer CSRs ---- */
#define CSR_TCFG    0x41    /* Timer Config */
#define CSR_TVAL    0x42    /* Timer Value */
#define CSR_TICLR   0x44    /* Timer Clear */

/* TCFG bits */
#define TCFG_EN     (1UL << 0)     /* Timer enable */
#define TCFG_PERIOD (1UL << 1)     /* Periodic mode */
#define TCFG_INITVAL_SHIFT  2      /* Init value at bits [63:2] */

/* ---- ECFG interrupt enable bits ---- */
#define ECFG_TIMER_IE  (1UL << 11)  /* Timer interrupt enable (bit 11) */

/* ---- CRMD interrupt enable ---- */
#define CRMD_IE       (1UL << 0)    /* Global interrupt enable */

/* ---- Simple delay loop for cooperative scheduling ---- */
static void delay_loop(uint64_t count)
{
    volatile uint64_t i;
    for (i = 0; i < count; i++)
        ;
}

/* ---- Timer API ---- */

void timer_enable(void)
{
    /*
     * Configure the LoongArch constant timer in periodic mode.
     * Timer interrupts are not yet enabled because the EIOINTC
     * setup is not complete.  We rely on cooperative scheduling
     * for now.
     */

    /* Set up the timer: periodic mode, init value = TIMER_INTERVAL */
    uint64_t tcfg = (TIMER_INTERVAL << TCFG_INITVAL_SHIFT) | TCFG_PERIOD | TCFG_EN;
    csr_write(0x41, tcfg);  /* CSR_TCFG */

    uart_puts("[TIMER] LoongArch timer configured (cooperative mode), interval=");
    uart_put_dec(TIMER_INTERVAL);
    uart_puts("\n");
}

void timer_reset(void)
{
    /*
     * Clear the timer interrupt pending bit.
     * In periodic mode, the timer automatically reloads.
     */
    csr_write(0x44, 1UL);  /* CSR_TICLR: clear timer interrupt */
}

/*
 * sched_cooperative_tick - Cooperative scheduling tick
 *
 * Called by threads to voluntarily trigger a scheduling round.
 * This is used on LoongArch as a fallback when timer interrupts
 * are not yet working properly.
 */
void sched_cooperative_tick(void)
{
    /* Small delay to simulate time passing */
    delay_loop(500000);

    /* Trigger a schedule: yield the CPU to allow other threads to run */
    struct proc *cur = proc_current();
    if (cur) {
        cur->ticks++;
        cur->total_ticks++;
        /* Always yield in cooperative mode to ensure fair scheduling */
        cur->state = PROC_READY;
        schedule();
    }
}

/*
 * timer_get_ticks - Read the LoongArch stable counter
 *
 * The stable counter increments at a constant frequency (100 MHz on
 * QEMU virt), providing a high-resolution monotonic counter for
 * benchmark timing.
 *
 * rdtime.d rd, rj reads the 64-bit stable counter into rd and the
 * upper 64 bits (always 0 on LA64) into rj.  We discard the upper
 * half by writing it to $r0 (the zero register).
 *
 * Note: $r0 must be used, not $0 — older LoongArch binutils rejects
 * the $0 shorthand.
 */
uint64_t timer_get_ticks(void)
{
    uint64_t val;
    asm volatile("rdtime.d %0, $r0" : "=r"(val));
    return val;
}

