static struct file *console_file;  /* /dev/console file handle */

/* Helper: string length (kernel has no libc) */
static int kstrlen(const char *s)
{
    int n = 0;
    while (*s++) n++;
    return n;
}

/* Helper: print string via VFS write to /dev/console */
void kprint(const char *s)
{
    if (console_file)
        vfs_write(console_file, s, (uint64_t)kstrlen(s));
}

/* Helper: print decimal number via VFS */
void kprint_dec(uint64_t val)
{
    char buf[21];
    int i = 20;
    buf[20] = '\0';
    if (val == 0) { kprint("0"); return; }
    while (val > 0 && i > 0) {
        buf[--i] = '0' + (val % 10);
        val /= 10;
    }
    kprint(&buf[i]);
}

/*
 * kprint_fixed - Print a fixed-point decimal number via VFS.
 * Prints val with `digits` decimal places.  Internally works with
 * scaled integers so no floating-point library is needed.
 *
 * Example: kprint_fixed(1048576000, 2) -> "10485760.00"
 */
void kprint_fixed(uint64_t val, int digits)
{
    /* Build the scale factor (10^digits) */
    uint64_t scale = 1;
    int d;
    for (d = 0; d < digits; d++)
        scale *= 10;

    /* Integer part */
    uint64_t int_part = val / scale;
    /* Fractional part */
    uint64_t frac_part = val % scale;

    /* Print integer part */
    kprint_dec(int_part);

    /* Print decimal point and fractional part */
    if (digits > 0) {
        kprint(".");
        /* Print fractional part with leading zeros */
        char buf[21];
        int i = digits;
        buf[digits] = '\0';
        while (i > 0) {
            buf[--i] = '0' + (frac_part % 10);
            frac_part /= 10;
        }
        kprint(buf);
    }
}

/* ===================================================================== */
/* Real benchmark measurement infrastructure                             */
/* ===================================================================== */

/*
 * The QEMU virt timer runs at 10 MHz (RISC-V) or 100 MHz (LoongArch).
 * We use a conservative 10 MHz estimate so throughput values are
 * computed from REAL elapsed timer ticks.
 */
#define TIMER_FREQ_HZ   10000000ULL

/*
 * bench_ticks_to_us - Convert timer ticks to microseconds (integer).
 */
static uint64_t bench_ticks_to_us(uint64_t ticks)
{
    if (ticks == 0) return 1;  /* avoid division by zero */
    return ticks / (TIMER_FREQ_HZ / 1000000ULL);
}

/*
 * bench_ticks_to_ns - Convert timer ticks to nanoseconds (integer).
 */
static uint64_t bench_ticks_to_ns(uint64_t ticks)
{
    if (ticks == 0) return 1;
    return ticks * 1000ULL / (TIMER_FREQ_HZ / 1000000ULL);
}

/*
 * bench_throughput_kbps - Compute throughput in kB/sec from bytes and ticks.
 * Returns a value scaled by 100 (i.e. 10485760000 means 104857600.00 kB/sec).
 * This avoids floating-point while preserving 2 decimal places.
 */
static uint64_t bench_throughput_kbps_100(uint64_t bytes, uint64_t ticks)
{
    if (ticks == 0) ticks = 1;
    /* bytes * TIMER_FREQ_HZ / ticks / 1024 / 100  (scaled by 100) */
    /* To avoid overflow, compute step by step */
    uint64_t result = bytes * 100ULL;        /* scale up */
    result = result / 1024ULL;               /* bytes -> kB */
    result = result * (TIMER_FREQ_HZ / 1000ULL);  /* multiply by freq/1000 to keep precision */
    result = result / (ticks / 1000ULL + 1); /* divide by ticks/1000 */
    return result;
}

/*
 * bench_file_write - Perform a real file write benchmark.
 * Writes `total_bytes` in `record_size` chunks to a file, measuring
 * elapsed timer ticks.  Returns throughput in kB/sec (scaled x100).
 */
static uint64_t bench_file_write(int fd, uint64_t total_bytes,
                                  uint64_t record_size)
{
    static char wbuf[4096];
    uint64_t written = 0;
    uint64_t i;
    uint64_t start, end;

    /* Fill write buffer with a pattern */
    for (i = 0; i < record_size && i < sizeof(wbuf); i++)
        wbuf[i] = (char)(i & 0xFF);

    start = timer_get_ticks();
    while (written < total_bytes) {
        uint64_t to_write = record_size;
        if (to_write > sizeof(wbuf))
            to_write = sizeof(wbuf);
        if (written + to_write > total_bytes)
            to_write = total_bytes - written;
        int64_t ret = ksyscall(SYS_write, (uint64_t)fd, (uint64_t)wbuf, to_write);
        if (ret <= 0) break;
        written += (uint64_t)ret;
    }
    end = timer_get_ticks();

    return bench_throughput_kbps_100(written, end - start);
}

/*
 * bench_file_read - Perform a real file read benchmark.
 * Reads `total_bytes` in `record_size` chunks from a file, measuring
 * elapsed timer ticks.  Returns throughput in kB/sec (scaled x100).
 */
static uint64_t bench_file_read(int fd, uint64_t total_bytes,
                                 uint64_t record_size)
{
    static char rbuf[4096];
    uint64_t read_bytes = 0;
    uint64_t start, end;

    start = timer_get_ticks();
    while (read_bytes < total_bytes) {
        uint64_t to_read = record_size;
        if (to_read > sizeof(rbuf))
            to_read = sizeof(rbuf);
        if (read_bytes + to_read > total_bytes)
            to_read = total_bytes - read_bytes;
        int64_t ret = ksyscall(SYS_read, (uint64_t)fd, (uint64_t)rbuf, to_read);
        if (ret <= 0) break;
        read_bytes += (uint64_t)ret;
    }
    end = timer_get_ticks();

    return bench_throughput_kbps_100(read_bytes, end - start);
}

