/*
 * bench_pipe_throughput - Measure real pipe data transfer throughput.
 * Writes `total_bytes` through a pipe and returns throughput in kB/sec
 * (scaled x100).
 */
static uint64_t bench_pipe_throughput_kbps_100(uint64_t total_bytes)
{
    int pipe_fds[2];
    static char pbuf[4096];
    uint64_t transferred = 0;
    uint64_t start, end;
    int i;

    for (i = 0; i < (int)sizeof(pbuf); i++)
        pbuf[i] = (char)(i & 0xFF);

    if (ksyscall(SYS_pipe, (uint64_t)pipe_fds, 0, 0) < 0)
        return 0;

    start = timer_get_ticks();
    while (transferred < total_bytes) {
        uint64_t to_write = sizeof(pbuf);
        if (transferred + to_write > total_bytes)
            to_write = total_bytes - transferred;
        int64_t wr = ksyscall(SYS_write, (uint64_t)pipe_fds[1],
                              (uint64_t)pbuf, to_write);
        if (wr <= 0) break;
        int64_t rd = ksyscall(SYS_read, (uint64_t)pipe_fds[0],
                              (uint64_t)pbuf, (uint64_t)wr);
        if (rd <= 0) break;
        transferred += (uint64_t)rd;
    }
    end = timer_get_ticks();

    ksyscall(SYS_close, (uint64_t)pipe_fds[0], 0, 0);
    ksyscall(SYS_close, (uint64_t)pipe_fds[1], 0, 0);

    return bench_throughput_kbps_100(transferred, end - start);
}

