/* Yield test: 3 children each print and yield 5 times */
static int yield_child_id[MAX_PROCS];

static void yield_child_fn(void *arg)
{
    (void)arg;
    int64_t pid = ksyscall(SYS_getpid, 0, 0, 0);
    int id = yield_child_id[pid];
    int i;
    for (i = 0; i < 5; i++) {
        kprint("  I am child process: ");
        kprint_dec((uint64_t)id);
        kprint(". iteration ");
        kprint_dec((uint64_t)i);
        kprint(".\n");
        ksyscall(SYS_yield, 0, 0, 0);
    }
    ksyscall(SYS_exit, 0, 0, 0);
}

