void test_runner_run(void)
{
    int i;
    int n;
    struct proc *p;

    /* Open /dev/console through the VFS layer for all test output */
    console_file = vfs_open("/dev/console", O_RDWR);
    if (!console_file) {
        uart_puts("[TEST] FATAL: cannot open /dev/console\n");
        return;
    }

    /*
     * Set up stdin (fd 0), stdout (fd 1), stderr (fd 2) as /dev/console
     * so that the first open() call in tests returns fd 3, matching the
     * expected "open fd:3" output.
     */
    p = proc_current();
    if (p) {
        p->fds[0] = vfs_open("/dev/console", O_RDWR);
        p->fds[1] = vfs_open("/dev/console", O_RDWR);
        p->fds[2] = vfs_open("/dev/console", O_RDWR);
