    for (i = 0; i < n; i++) {
        const test_script_t *s = &discovered_scripts[i];
        group_start(s->group);
        switch (s->kind) {
        case TEST_BASIC:      basic_tests();      break;
        case TEST_BUSYBOX:    busybox_tests();    break;
        case TEST_LUA:        lua_tests();        break;
        case TEST_IOZONE:     iozone_tests();     break;
